import { useState } from "react";
import type { FacetGroup } from "./types";

type FacetSidebarProps = {
  groups: FacetGroup[];
  selected: Record<string, Set<string>>;
  onToggle: (groupKey: string, value: string) => void;
};

export function FacetSidebar({ groups, selected, onToggle }: FacetSidebarProps) {
  const [collapsed, setCollapsed] = useState<Set<string>>(new Set());

  const toggle = (key: string) => {
    setCollapsed((prev) => {
      const next = new Set(prev);
      next.has(key) ? next.delete(key) : next.add(key);
      return next;
    });
  };

  return (
    <div className="facets">
      {groups.map((g) => {
        const isOpen = !collapsed.has(g.key);
        const sel = selected[g.key];
        return (
          <div key={g.key} className="facets__group">
            <button
              className="facets__header"
              onClick={() => toggle(g.key)}
              aria-expanded={isOpen}
            >
              <span className={`facets__chevron ${isOpen ? "facets__chevron--open" : ""}`}>
                &#9654;
              </span>
              <span className="facets__label">{g.label}</span>
              <span className="facets__badge">{g.values.length}</span>
            </button>
            {isOpen ? (
              <ul className="facets__list">
                {g.values.map((v) => {
                  const checked = sel?.has(v.value) ?? false;
                  return (
                    <li key={v.value} className="facets__item">
                      <label className="facets__item-label">
                        <input
                          type="checkbox"
                          checked={checked}
                          onChange={() => onToggle(g.key, v.value)}
                          className="facets__checkbox"
                        />
                        <span className="facets__value">{v.value || "(empty)"}</span>
                        <span className="facets__count">{v.count}</span>
                      </label>
                    </li>
                  );
                })}
              </ul>
            ) : null}
          </div>
        );
      })}
      {groups.length === 0 ? (
        <p className="facets__empty">No facets available</p>
      ) : null}
    </div>
  );
}
