import { useState, useMemo, useCallback, useRef } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import type { LogsRequest, TracesRequest } from "../telemetry/types";
import { buildWaterfallTrace, type WaterfallTrace } from "./waterfall-layout";
import { TraceWaterfall } from "./TraceWaterfall";
import { SpanDetailsPanel } from "./SpanDetailsPanel";
import { TraceLogCorrelation } from "./TraceLogCorrelation";
import { ComponentMap, type MapSelection } from "./ComponentMap";
import { useKeyboardShortcuts } from "../hooks/useKeyboardShortcuts";
import { ExplorerLayout, FacetSidebar, SearchBar, DetailPanel } from "../layout";
import { extractTraceFacets, applyFacetFilters } from "./trace-filters";

type ViewMode = "list" | "map";

type TracesTabProps = {
  logs: LogsRequest;
  telemetryError: string | null;
  traces: TracesRequest;
  onInteract?: () => void;
};

export function TracesTab({ logs, telemetryError, traces, onInteract }: TracesTabProps) {
  const [selectedTraceId, setSelectedTraceId] = useState<string | null>(null);
  const [selectedSpanId, setSelectedSpanId] = useState<string | null>(null);
  const [collapsedSpans, setCollapsedSpans] = useState<Set<string>>(new Set());
  const [facetSelection, setFacetSelection] = useState<Record<string, Set<string>>>({});
  const [search, setSearch] = useState("");
  const [viewMode, setViewMode] = useState<ViewMode>("list");
  const [mapSelection, setMapSelection] = useState<MapSelection>(null);
  const searchRef = useRef<HTMLInputElement>(null);
  const tableRef = useRef<HTMLDivElement>(null);

  const allTraces: WaterfallTrace[] = useMemo(() => {
    return traces.resourceSpans
      .map((rs) => buildWaterfallTrace(rs))
      .sort((a, b) => {
        const aStart = a.spans[0]?.startTimeUnixNano ?? "";
        const bStart = b.spans[0]?.startTimeUnixNano ?? "";
        if (aStart > bStart) return -1;
        if (aStart < bStart) return 1;
        return a.traceId.localeCompare(b.traceId);
      });
  }, [traces]);

  const facets = useMemo(() => extractTraceFacets(allTraces), [allTraces]);
  const filteredTraces = useMemo(
    () => applyFacetFilters(allTraces, facetSelection, search),
    [allTraces, facetSelection, search],
  );

  // Apply map selection filter on top of facet/search filters
  const displayTraces = useMemo(() => {
    if (!mapSelection) return filteredTraces;
    return filteredTraces.filter((t) => mapSelection.traceIds.has(t.traceId));
  }, [filteredTraces, mapSelection]);

  const selectedTrace = displayTraces.find((t) => t.traceId === selectedTraceId) ?? null;
  const selectedSpan = selectedTrace?.spans.find((s) => s.spanId === selectedSpanId) ?? null;

  function handleToggleFacet(groupKey: string, value: string) {
    setFacetSelection((prev) => {
      const next = { ...prev };
      const set = new Set(prev[groupKey] ?? []);
      set.has(value) ? set.delete(value) : set.add(value);
      if (set.size === 0) {
        delete next[groupKey];
      } else {
        next[groupKey] = set;
      }
      return next;
    });
  }

  function handleClearFacet(groupKey: string, value: string) {
    handleToggleFacet(groupKey, value);
  }

  function handleSelectTrace(traceId: string) {
    setSelectedTraceId(traceId);
    setSelectedSpanId(null);
    setCollapsedSpans(new Set());
    onInteract?.();
  }

  function handleToggleCollapse(spanId: string) {
    setCollapsedSpans((prev) => {
      const next = new Set(prev);
      next.has(spanId) ? next.delete(spanId) : next.add(spanId);
      return next;
    });
  }

  const navigateTraceList = useCallback(
    (direction: 1 | -1) => {
      if (displayTraces.length === 0) return;
      const idx = displayTraces.findIndex((t) => t.traceId === selectedTraceId);
      const next =
        idx === -1
          ? direction === 1
            ? 0
            : displayTraces.length - 1
          : Math.max(0, Math.min(displayTraces.length - 1, idx + direction));
      setSelectedTraceId(displayTraces[next].traceId);
      setSelectedSpanId(null);
    },
    [displayTraces, selectedTraceId],
  );

  const navigateSpans = useCallback(
    (direction: 1 | -1) => {
      if (!selectedTrace) return;
      const spans = selectedTrace.spans;
      if (spans.length === 0) return;
      const idx = spans.findIndex((s) => s.spanId === selectedSpanId);
      const next =
        idx === -1
          ? direction === 1
            ? 0
            : spans.length - 1
          : Math.max(0, Math.min(spans.length - 1, idx + direction));
      setSelectedSpanId(spans[next].spanId);
    },
    [selectedTrace, selectedSpanId],
  );

  useKeyboardShortcuts(
    useMemo(
      () => ({
        "/": () => searchRef.current?.focus(),
        Escape: () => {
          if (selectedSpanId) setSelectedSpanId(null);
          else if (selectedTraceId) setSelectedTraceId(null);
        },
        ArrowUp: () => navigateTraceList(-1),
        ArrowDown: () => navigateTraceList(1),
        ArrowLeft: () => navigateSpans(-1),
        ArrowRight: () => navigateSpans(1),
        c: () => {
          const text = selectedSpanId ?? selectedTraceId;
          if (text) navigator.clipboard.writeText(text);
        },
      }),
      [selectedSpanId, selectedTraceId, navigateTraceList, navigateSpans],
    ),
  );

  const virtualizer = useVirtualizer({
    count: displayTraces.length,
    getScrollElement: () => tableRef.current,
    estimateSize: () => 36,
    overscan: 10,
  });

  const hasActiveFacets = Object.keys(facetSelection).length > 0;

  // Sidebar
  const sidebar = (
    <FacetSidebar groups={facets} selected={facetSelection} onToggle={handleToggleFacet} />
  );

  // Detail panel (right)
  const panel = selectedTrace ? (
    <DetailPanel
      title={selectedTrace.rootSpanName}
      subtitle={`${selectedTrace.serviceName} · ${selectedTrace.spanCount} spans · ${selectedTrace.durationMs?.toFixed(1) ?? "--"}ms`}
      onClose={() => setSelectedTraceId(null)}
    >
      <TraceWaterfall
        trace={selectedTrace}
        selectedSpanId={selectedSpanId}
        onSelectSpan={setSelectedSpanId}
        collapsedSpans={collapsedSpans}
        onToggleCollapse={handleToggleCollapse}
      />
      {selectedSpan ? (
        <SpanDetailsPanel span={selectedSpan} onClose={() => setSelectedSpanId(null)} />
      ) : null}
      <TraceLogCorrelation logs={logs} traceId={selectedTrace.traceId} />
    </DetailPanel>
  ) : undefined;

  return (
    <section className="tab-panel" role="tabpanel">
      <ExplorerLayout sidebar={sidebar} panel={panel}>
        <SearchBar
          value={search}
          onChange={setSearch}
          placeholder="Filter traces by ID, service, operation..."
          inputRef={searchRef}
          activeFacets={hasActiveFacets ? facetSelection : undefined}
          onClearFacet={handleClearFacet}
        />

        <div className="explorer__toolbar">
          <span className="explorer__count">
            {displayTraces.length === allTraces.length
              ? `${allTraces.length} traces`
              : `${displayTraces.length} of ${allTraces.length} traces`}
          </span>
          <div className="view-toggle">
            <button
              className={`view-toggle__btn ${viewMode === "list" ? "view-toggle__btn--active" : ""}`}
              onClick={() => setViewMode("list")}
              type="button"
            >
              List
            </button>
            <button
              className={`view-toggle__btn ${viewMode === "map" ? "view-toggle__btn--active" : ""}`}
              onClick={() => setViewMode("map")}
              type="button"
            >
              Map
            </button>
          </div>
        </div>

        {telemetryError ? <p className="explorer__status explorer__status--error">{telemetryError}</p> : null}
        {allTraces.length === 0 && !telemetryError ? (
          <p className="explorer__status">Waiting for traces... Send OTLP data to port 4318.</p>
        ) : null}

        {viewMode === "map" ? (
          <ComponentMap traces={filteredTraces} selection={mapSelection} onSelect={setMapSelection} />
        ) : (
          <>
            {/* Map filter pill in list view */}
            {mapSelection ? (
              <div className="component-map__filter-pill">
                <span className="component-map__filter-label">
                  {mapSelection.type === "node"
                    ? `Filtered by component: ${mapSelection.label}`
                    : `Filtered by connection: ${mapSelection.sourceLabel} \u2192 ${mapSelection.targetLabel}`}
                </span>
                <button className="component-map__filter-close" onClick={() => setMapSelection(null)} type="button">
                  &times;
                </button>
              </div>
            ) : null}

            {/* Table header */}
            <div className="data-table__head">
              <span className="data-table__th data-table__th--status"></span>
              <span className="data-table__th data-table__th--id">Trace ID</span>
              <span className="data-table__th data-table__th--service">Service</span>
              <span className="data-table__th data-table__th--operation">Operation</span>
              <span className="data-table__th data-table__th--duration">Duration</span>
              <span className="data-table__th data-table__th--spans">Spans</span>
            </div>

            {/* Table body (virtualized) */}
            <div className="data-table__body" ref={tableRef}>
              <div style={{ height: virtualizer.getTotalSize(), position: "relative" }}>
                {virtualizer.getVirtualItems().map((vi) => {
                  const t = displayTraces[vi.index];
                  const active = t.traceId === selectedTraceId;
                  return (
                    <button
                      key={t.traceId}
                      className={`data-table__row ${active ? "data-table__row--active" : ""}`}
                      onClick={() => handleSelectTrace(t.traceId)}
                      type="button"
                      style={{
                        position: "absolute",
                        top: 0,
                        left: 0,
                        width: "100%",
                        transform: `translateY(${vi.start}px)`,
                      }}
                      data-index={vi.index}
                      ref={virtualizer.measureElement}
                    >
                      <span className="data-table__td data-table__td--status">
                        <span className={`status-dot status-dot--${t.status}`} />
                      </span>
                      <span className="data-table__td data-table__td--id">{t.traceId.slice(0, 12)}</span>
                      <span className="data-table__td data-table__td--service">{t.serviceName}</span>
                      <span className="data-table__td data-table__td--operation">{t.rootSpanName}</span>
                      <span className="data-table__td data-table__td--duration">
                        {t.durationMs !== null ? `${t.durationMs.toFixed(1)}ms` : "--"}
                      </span>
                      <span className="data-table__td data-table__td--spans">{t.spanCount}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          </>
        )}
      </ExplorerLayout>
    </section>
  );
}
