import { type WaterfallSpan, type WaterfallTrace, formatDurationMs } from "./waterfall-layout";

type TraceTimelineProps = {
  trace: WaterfallTrace;
  selectedSpanId: string | null;
  onSelectSpan: (spanId: string) => void;
};

export function TraceTimeline({ trace, selectedSpanId, onSelectSpan }: TraceTimelineProps) {
  const services = [...new Set(trace.spans.map((s) => s.resource.serviceName))];
  const laneHeight = 36;
  const headerHeight = 28;
  const totalHeight = headerHeight + services.length * laneHeight + 8;

  return (
    <div className="timeline">
      <div className="timeline__header">
        <div className="timeline__header-left">
          <span className="waterfall__trace-id">Trace {trace.traceId}</span>
          <span className="waterfall__span-count">{trace.spanCount} spans</span>
          <span className={`trace-status trace-status--${trace.status}`}>{trace.status}</span>
        </div>
        <div className="timeline__header-right">
          <span className="waterfall__duration">{formatDurationMs(trace.durationMs)}</span>
        </div>
      </div>

      <div className="timeline__body" style={{ height: totalHeight }}>
        {/* Service lane labels */}
        <div className="timeline__lanes">
          {services.map((svc, i) => (
            <div
              key={svc}
              className="timeline__lane-label"
              style={{ top: headerHeight + i * laneHeight, height: laneHeight }}
            >
              {svc}
            </div>
          ))}
        </div>

        {/* Time axis header */}
        <div className="timeline__axis" style={{ height: headerHeight }}>
          <span>0ms</span>
          <span>{formatDurationMs(trace.durationMs)}</span>
        </div>

        {/* Span boxes */}
        <div className="timeline__canvas" style={{ top: headerHeight }}>
          {services.map((svc, laneIdx) => (
            <div
              key={svc}
              className="timeline__lane"
              style={{ top: laneIdx * laneHeight, height: laneHeight }}
            >
              {trace.spans
                .filter((s) => s.resource.serviceName === svc)
                .map((span) => (
                  <TimelineSpan
                    key={span.spanId}
                    span={span}
                    isSelected={span.spanId === selectedSpanId}
                    onSelect={() => onSelectSpan(span.spanId)}
                  />
                ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function TimelineSpan({ span, isSelected, onSelect }: { span: WaterfallSpan; isSelected: boolean; onSelect: () => void }) {
  const statusClass = span.status.code === 2 ? "error" : span.status.code === 1 ? "ok" : "unset";
  const width = Math.max(span.durationPercent, 0.5);

  return (
    <button
      className={`timeline__span timeline__span--${statusClass} ${isSelected ? "timeline__span--selected" : ""}`}
      style={{
        left: `${span.offsetPercent}%`,
        width: `${width}%`,
      }}
      onClick={onSelect}
      title={`${span.name} (${formatDurationMs(span.durationMs)})`}
      type="button"
    >
      <span className="timeline__span-label">{span.name}</span>
    </button>
  );
}
