import { useMemo, useState } from "react";
import type { WaterfallTrace } from "./waterfall-layout";
import { buildComponentGraph, NODE_WIDTH, NODE_HEIGHT, type GraphNode, type GraphEdge } from "./component-map-layout";

export type MapSelection =
  | { type: "node"; nodeId: string; label: string; traceIds: Set<string> }
  | { type: "edge"; edgeKey: string; sourceLabel: string; targetLabel: string; traceIds: Set<string> }
  | null;

type ComponentMapProps = {
  traces: WaterfallTrace[];
  selection: MapSelection;
  onSelect: (selection: MapSelection) => void;
};

export function ComponentMap({ traces, selection, onSelect }: ComponentMapProps) {
  const graph = useMemo(() => buildComponentGraph(traces), [traces]);
  const [hoveredNode, setHoveredNode] = useState<string | null>(null);
  const [hoveredEdge, setHoveredEdge] = useState<string | null>(null);

  if (graph.nodes.length === 0) {
    return (
      <div className="component-map component-map--empty">
        <p>Waiting for trace data to build the component map...</p>
      </div>
    );
  }

  const nodeById = new Map(graph.nodes.map((n) => [n.id, n]));

  // Find connected edges for a hovered node
  const connectedEdgeKeys = new Set<string>();
  const connectedNodeIds = new Set<string>();
  const activeNode = hoveredNode ?? (selection?.type === "node" ? selection.nodeId : null);
  if (activeNode) {
    connectedNodeIds.add(activeNode);
    for (const e of graph.edges) {
      if (e.sourceId === activeNode || e.targetId === activeNode) {
        connectedEdgeKeys.add(`${e.sourceId}→${e.targetId}`);
        connectedNodeIds.add(e.sourceId);
        connectedNodeIds.add(e.targetId);
      }
    }
  }
  // Also highlight both nodes of a selected edge
  const activeEdgeKey = hoveredEdge ?? (selection?.type === "edge" ? selection.edgeKey : null);
  if (activeEdgeKey && !activeNode) {
    const [src, tgt] = activeEdgeKey.split("→");
    connectedNodeIds.add(src);
    connectedNodeIds.add(tgt);
    connectedEdgeKeys.add(activeEdgeKey);
  }

  const hasDimming = activeNode !== null || activeEdgeKey !== null;

  function handleClickNode(node: GraphNode) {
    if (selection?.type === "node" && selection.nodeId === node.id) {
      onSelect(null); // deselect
      return;
    }
    const traceIds = graph.nodeTraces.get(node.id) ?? new Set();
    onSelect({ type: "node", nodeId: node.id, label: node.label, traceIds });
  }

  function handleClickEdge(edge: GraphEdge) {
    const edgeKey = `${edge.sourceId}→${edge.targetId}`;
    if (selection?.type === "edge" && selection.edgeKey === edgeKey) {
      onSelect(null); // deselect
      return;
    }
    const source = nodeById.get(edge.sourceId);
    const target = nodeById.get(edge.targetId);
    const traceIds = graph.edgeTraces.get(edgeKey) ?? new Set();
    onSelect({
      type: "edge",
      edgeKey,
      sourceLabel: source?.label ?? edge.sourceId,
      targetLabel: target?.label ?? edge.targetId,
      traceIds,
    });
  }

  return (
    <div className="component-map">
      <div className="component-map__header">
        <span className="component-map__title">Component Map</span>
        <span className="component-map__subtitle">
          {graph.nodes.length} components · {graph.edges.length} connections
        </span>
        {selection ? (
          <button className="component-map__clear-btn" onClick={() => onSelect(null)} type="button">
            Clear filter
          </button>
        ) : (
          <span className="component-map__hint">Click a component or connection to filter traces</span>
        )}
      </div>

      {/* Selection pill */}
      {selection ? (
        <div className="component-map__filter-pill">
          <span className="component-map__filter-label">
            {selection.type === "node"
              ? `Showing ${selection.traceIds.size} traces through ${selection.label}`
              : `Showing ${selection.traceIds.size} traces between ${selection.sourceLabel} → ${selection.targetLabel}`}
          </span>
          <button className="component-map__filter-close" onClick={() => onSelect(null)} type="button">
            &times;
          </button>
        </div>
      ) : null}

      <div className="component-map__canvas">
        <svg
          width={graph.width}
          height={graph.height}
          viewBox={`0 0 ${graph.width} ${graph.height}`}
          className="component-map__svg"
        >
          <defs>
            <marker id="arrowhead" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
              <polygon points="0 0, 8 3, 0 6" fill="var(--text-dim)" />
            </marker>
            <marker id="arrowhead-active" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
              <polygon points="0 0, 8 3, 0 6" fill="var(--accent)" />
            </marker>
            <marker id="arrowhead-error" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
              <polygon points="0 0, 8 3, 0 6" fill="#f44747" />
            </marker>
          </defs>

          {/* Edges */}
          {graph.edges.map((edge) => {
            const edgeKey = `${edge.sourceId}→${edge.targetId}`;
            const isSelected = selection?.type === "edge" && selection.edgeKey === edgeKey;
            return (
              <EdgeLine
                key={edgeKey}
                edge={edge}
                nodeById={nodeById}
                hovered={hoveredEdge === edgeKey}
                selected={isSelected}
                dimmed={hasDimming && !connectedEdgeKeys.has(edgeKey)}
                onHover={(h) => setHoveredEdge(h ? edgeKey : null)}
                onClick={() => handleClickEdge(edge)}
              />
            );
          })}

          {/* Nodes */}
          {graph.nodes.map((node) => {
            const isSelected = selection?.type === "node" && selection.nodeId === node.id;
            return (
              <NodeBox
                key={node.id}
                node={node}
                hovered={hoveredNode === node.id}
                selected={isSelected}
                dimmed={hasDimming && !connectedNodeIds.has(node.id)}
                onHover={(h) => setHoveredNode(h ? node.id : null)}
                onClick={() => handleClickNode(node)}
              />
            );
          })}
        </svg>
      </div>
    </div>
  );
}

// ── Node ──────────────────────────────────────────────────

const KIND_ICON: Record<string, string> = {
  service: "\u2B22",    // hexagon
  database: "\u2395",   // apl quad
  cache: "\u26A1",      // lightning
  http: "\u2B95",       // arrow
  messaging: "\u2709",  // envelope
};

const KIND_COLOR: Record<string, string> = {
  service: "var(--accent)",
  database: "var(--purple)",
  cache: "var(--yellow)",
  http: "var(--blue)",
  messaging: "var(--orange)",
};

function NodeBox({ node, hovered, selected, dimmed, onHover, onClick }: {
  node: GraphNode;
  hovered: boolean;
  selected: boolean;
  dimmed: boolean;
  onHover: (h: boolean) => void;
  onClick: () => void;
}) {
  const errorRate = node.calls > 0 ? node.errors / node.calls : 0;
  const hasErrors = node.errors > 0;
  const active = hovered || selected;

  return (
    <g
      className={`component-map__node ${active ? "component-map__node--hovered" : ""} ${dimmed ? "component-map__node--dimmed" : ""}`}
      onMouseEnter={() => onHover(true)}
      onMouseLeave={() => onHover(false)}
      onClick={onClick}
      style={{ cursor: "pointer" }}
    >
      <rect
        x={node.x}
        y={node.y}
        width={NODE_WIDTH}
        height={NODE_HEIGHT}
        rx={8}
        ry={8}
        className="component-map__node-bg"
        stroke={selected ? "var(--accent)" : hasErrors && errorRate > 0.1 ? "#f44747" : active ? "var(--accent)" : "var(--border)"}
        strokeWidth={selected ? 2.5 : active ? 2 : 1}
      />

      {/* Kind icon + color indicator */}
      <text
        x={node.x + 14}
        y={node.y + 28}
        className="component-map__node-icon"
        fill={KIND_COLOR[node.kind] ?? "var(--text-dim)"}
        fontSize={16}
      >
        {KIND_ICON[node.kind] ?? "\u2022"}
      </text>

      {/* Label */}
      <text
        x={node.x + 34}
        y={node.y + 28}
        className="component-map__node-label"
        fill="var(--text)"
      >
        {truncate(node.label, 22)}
      </text>

      {/* Sublabel */}
      <text
        x={node.x + 34}
        y={node.y + 46}
        className="component-map__node-sublabel"
        fill="var(--text-dim)"
        fontSize={11}
      >
        {truncate(node.sublabel, 26)}
      </text>

      {/* Stats row */}
      <text
        x={node.x + 14}
        y={node.y + 66}
        className="component-map__node-stats"
        fill="var(--text-soft)"
        fontSize={10}
      >
        {node.calls} calls · {fmtDuration(node.avgDurationMs)}
        {hasErrors ? ` · ${node.errors} err` : ""}
      </text>

      {/* Error rate indicator bar */}
      {hasErrors ? (
        <rect
          x={node.x}
          y={node.y + NODE_HEIGHT - 3}
          width={NODE_WIDTH * Math.min(errorRate, 1)}
          height={3}
          rx={0}
          ry={0}
          fill="#f44747"
          opacity={0.8}
        />
      ) : null}
    </g>
  );
}

// ── Edge ──────────────────────────────────────────────────

function EdgeLine({ edge, nodeById, hovered, selected, dimmed, onHover, onClick }: {
  edge: GraphEdge;
  nodeById: Map<string, GraphNode>;
  hovered: boolean;
  selected: boolean;
  dimmed: boolean;
  onHover: (h: boolean) => void;
  onClick: () => void;
}) {
  const source = nodeById.get(edge.sourceId);
  const target = nodeById.get(edge.targetId);
  if (!source || !target) return null;

  // Source right center → target left center
  const x1 = source.x + NODE_WIDTH;
  const y1 = source.y + NODE_HEIGHT / 2;
  const x2 = target.x;
  const y2 = target.y + NODE_HEIGHT / 2;

  // Bezier curve control points
  const dx = (x2 - x1) * 0.5;
  const path = `M ${x1} ${y1} C ${x1 + dx} ${y1}, ${x2 - dx} ${y2}, ${x2} ${y2}`;

  const hasErrors = edge.errors > 0;
  const errorRate = edge.calls > 0 ? edge.errors / edge.calls : 0;
  const active = hovered || selected;
  const markerEnd = hasErrors && errorRate > 0.1
    ? "url(#arrowhead-error)"
    : active ? "url(#arrowhead-active)" : "url(#arrowhead)";

  // Midpoint for label
  const mx = (x1 + x2) / 2;
  const my = (y1 + y2) / 2;

  return (
    <g
      className={`component-map__edge ${dimmed ? "component-map__edge--dimmed" : ""}`}
      onMouseEnter={() => onHover(true)}
      onMouseLeave={() => onHover(false)}
      onClick={onClick}
      style={{ cursor: "pointer" }}
    >
      {/* Wider invisible hit area */}
      <path d={path} fill="none" stroke="transparent" strokeWidth={12} />
      <path
        d={path}
        fill="none"
        stroke={hasErrors && errorRate > 0.1 ? "#f44747" : active ? "var(--accent)" : "var(--text-dim)"}
        strokeWidth={selected ? 2.5 : active ? 2 : 1}
        strokeDasharray={hasErrors && errorRate > 0.1 ? "4 3" : undefined}
        markerEnd={markerEnd}
        opacity={dimmed ? 0.2 : active ? 1 : 0.6}
      />
      {/* Edge label */}
      {(active || edge.calls > 1) ? (
        <g>
          <rect
            x={mx - 30}
            y={my - 10}
            width={60}
            height={18}
            rx={4}
            fill="var(--chrome-2)"
            stroke={selected ? "var(--accent)" : "var(--border)"}
            strokeWidth={selected ? 1 : 0.5}
            opacity={dimmed ? 0.2 : 0.9}
          />
          <text
            x={mx}
            y={my + 3}
            textAnchor="middle"
            className="component-map__edge-label"
            fill={hasErrors ? "#f44747" : "var(--text-soft)"}
            fontSize={10}
            opacity={dimmed ? 0.2 : 1}
          >
            {edge.calls}× · {fmtDuration(edge.avgDurationMs)}
          </text>
        </g>
      ) : null}
    </g>
  );
}

// ── Helpers ───────────────────────────────────────────────

function truncate(s: string, max: number): string {
  return s.length > max ? s.slice(0, max - 1) + "\u2026" : s;
}

function fmtDuration(ms: number): string {
  if (ms < 1) return `${(ms * 1000).toFixed(0)}\u00B5s`;
  if (ms < 1000) return `${ms.toFixed(1)}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}
