import { useMemo } from "react";
import { getStringAttributeValue, type LogsRequest, type TelemetryAttribute } from "../telemetry/types";

type CorrelatedLog = {
  body: string;
  resource: string;
  severity: string;
  severityClass: string;
  spanId: string;
  timestamp: string;
  traceId: string;
};

type TraceLogCorrelationProps = {
  logs: LogsRequest;
  traceId: string;
};

function toHex(value: Uint8Array): string {
  if (!value || value.length === 0) return "";
  return Array.from(value, (b) => b.toString(16).padStart(2, "0")).join("");
}

function getSeverityClass(severity: string): string {
  const s = severity.toUpperCase();
  if (s.startsWith("ERROR") || s.startsWith("FATAL")) return "error";
  if (s.startsWith("WARN")) return "warn";
  if (s.startsWith("DEBUG") || s.startsWith("TRACE")) return "debug";
  return "info";
}

export function TraceLogCorrelation({ logs, traceId }: TraceLogCorrelationProps) {
  const correlatedLogs = useMemo(() => {
    const result: CorrelatedLog[] = [];
    const traceIdLower = traceId.toLowerCase();

    for (const resourceLog of logs.resourceLogs) {
      const resource = getStringAttribute(resourceLog.resource?.attributes, "service.name") ?? "unknown";
      for (const scopeLog of resourceLog.scopeLogs) {
        for (const record of scopeLog.logRecords) {
          const logTraceId = toHex(record.traceId);
          if (!logTraceId || !logTraceId.toLowerCase().startsWith(traceIdLower)) continue;

          const severity = record.severityText || "UNSPECIFIED";
          result.push({
            body: getStringAttributeValue({ key: "body", value: { value: record.body?.value } }) ?? "Structured payload",
            resource,
            severity,
            severityClass: getSeverityClass(severity),
            spanId: toHex(record.spanId),
            timestamp: record.timeUnixNano || record.observedTimeUnixNano || "0",
            traceId: logTraceId,
          });
        }
      }
    }

    result.sort((a, b) => {
      if (a.timestamp < b.timestamp) return -1;
      if (a.timestamp > b.timestamp) return 1;
      return 0;
    });

    return result;
  }, [logs, traceId]);

  if (correlatedLogs.length === 0) return null;

  return (
    <div className="trace-logs">
      <div className="trace-logs__header">
        <span className="trace-logs__title">Correlated Logs ({correlatedLogs.length})</span>
      </div>
      <div className="trace-logs__list">
        {correlatedLogs.map((log, i) => (
          <div key={`${log.timestamp}-${i}`} className="trace-logs__row">
            <span className={`trace-logs__severity trace-logs__severity--${log.severityClass}`}>
              {log.severity}
            </span>
            <span className="trace-logs__resource">{log.resource}</span>
            {log.spanId ? <span className="trace-logs__span-id">span:{log.spanId.slice(0, 8)}</span> : null}
            <span className="trace-logs__body">{log.body}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function getStringAttribute(
  attributes: ReadonlyArray<TelemetryAttribute> | undefined,
  key: string,
): string | undefined {
  const attribute = attributes?.find((entry) => entry.key === key);
  return getStringAttributeValue(attribute);
}
