type KeyboardHelpProps = {
  onClose: () => void;
};

const shortcuts = [
  { key: "/", description: "Focus search / filter input" },
  { key: "↑ / ↓", description: "Navigate trace list" },
  { key: "← / →", description: "Navigate spans in waterfall" },
  { key: "Enter", description: "Select / expand" },
  { key: "Esc", description: "Close details panel / clear selection" },
  { key: "c", description: "Copy selected trace or span ID" },
  { key: "?", description: "Toggle this help overlay" },
];

export function KeyboardHelp({ onClose }: KeyboardHelpProps) {
  return (
    <div className="keyboard-help__overlay" onClick={onClose} role="dialog" aria-label="Keyboard shortcuts">
      <div className="keyboard-help" onClick={(e) => e.stopPropagation()}>
        <div className="keyboard-help__header">
          <h3 className="keyboard-help__title">Keyboard Shortcuts</h3>
          <button className="keyboard-help__close" onClick={onClose} aria-label="Close">×</button>
        </div>
        <div className="keyboard-help__body">
          {shortcuts.map((s) => (
            <div key={s.key} className="keyboard-help__row">
              <kbd className="keyboard-help__key">{s.key}</kbd>
              <span className="keyboard-help__desc">{s.description}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
