import type { FacetGroup } from "../layout/types";
import type { WaterfallTrace } from "./waterfall-layout";

export function extractTraceFacets(traces: WaterfallTrace[]): FacetGroup[] {
  const services = new Map<string, number>();
  const statuses = new Map<string, number>();
  const spanNames = new Map<string, number>();
  const kinds = new Map<string, number>();

  for (const t of traces) {
    for (const s of t.spans) {
      inc(services, s.resource.serviceName || "unknown");
      inc(statuses, formatStatusCode(s.status.code));
      inc(spanNames, s.name);
      inc(kinds, s.kind);
    }
  }

  return [
    buildGroup("service", "Service", services),
    buildGroup("status", "Status", statuses),
    buildGroup("kind", "Span Kind", kinds),
    buildGroup("spanName", "Operation", spanNames, 15),
  ].filter((g) => g.values.length > 0);
}

export function applyFacetFilters(
  traces: WaterfallTrace[],
  selected: Record<string, Set<string>>,
  search: string,
): WaterfallTrace[] {
  const svc = selected["service"];
  const status = selected["status"];
  const kind = selected["kind"];
  const op = selected["spanName"];
  const q = search.toLowerCase().trim();

  return traces.filter((t) => {
    if (svc?.size && !t.spans.some((s) => svc.has(s.resource.serviceName || "unknown"))) return false;
    if (status?.size && !t.spans.some((s) => status.has(formatStatusCode(s.status.code)))) return false;
    if (kind?.size && !t.spans.some((s) => kind.has(s.kind))) return false;
    if (op?.size && !t.spans.some((s) => op.has(s.name))) return false;
    if (q) {
      const haystack = [
        t.traceId,
        t.rootSpanName,
        ...t.spans.map((s) => s.name),
        ...t.spans.map((s) => s.resource.serviceName),
      ]
        .join(" ")
        .toLowerCase();
      if (!haystack.includes(q)) return false;
    }
    return true;
  });
}

function formatStatusCode(code: number): string {
  switch (code) {
    case 0: return "unset";
    case 1: return "ok";
    case 2: return "error";
    default: return "unset";
  }
}

function inc(m: Map<string, number>, key: string) {
  m.set(key, (m.get(key) ?? 0) + 1);
}

function buildGroup(key: string, label: string, m: Map<string, number>, limit = 30): FacetGroup {
  const values = [...m.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, limit)
    .map(([value, count]) => ({ value, count }));
  return { key, label, values };
}
