import { type WaterfallSpan, type WaterfallTrace, formatDurationMs } from "./waterfall-layout";

type TraceWaterfallProps = {
  trace: WaterfallTrace;
  selectedSpanId: string | null;
  onSelectSpan: (spanId: string) => void;
  collapsedSpans: Set<string>;
  onToggleCollapse: (spanId: string) => void;
};

export function TraceWaterfall({ trace, selectedSpanId, onSelectSpan, collapsedSpans, onToggleCollapse }: TraceWaterfallProps) {
  const visibleSpans = getVisibleSpans(trace.spans, collapsedSpans);

  return (
    <div className="waterfall">
      <div className="waterfall__header">
        <div className="waterfall__header-left">
          <span className="waterfall__trace-id">Trace {trace.traceId}</span>
          <span className="waterfall__span-count">{trace.spanCount} spans</span>
          <span className={`trace-status trace-status--${trace.status}`}>{trace.status}</span>
        </div>
        <div className="waterfall__header-right">
          <span className="waterfall__duration">{formatDurationMs(trace.durationMs)}</span>
        </div>
      </div>

      <div className="waterfall__timeline-header">
        <div className="waterfall__col-service">Service / Operation</div>
        <div className="waterfall__col-timeline">
          <span>0ms</span>
          <span>{formatDurationMs(trace.durationMs)}</span>
        </div>
      </div>

      <div className="waterfall__rows">
        {visibleSpans.map((span) => (
          <WaterfallRow
            key={span.spanId}
            span={span}
            isSelected={span.spanId === selectedSpanId}
            hasChildren={span.children.length > 0}
            isCollapsed={collapsedSpans.has(span.spanId)}
            onSelect={() => onSelectSpan(span.spanId)}
            onToggle={() => onToggleCollapse(span.spanId)}
          />
        ))}
      </div>
    </div>
  );
}

type WaterfallRowProps = {
  span: WaterfallSpan;
  isSelected: boolean;
  hasChildren: boolean;
  isCollapsed: boolean;
  onSelect: () => void;
  onToggle: () => void;
};

function WaterfallRow({ span, isSelected, hasChildren, isCollapsed, onSelect, onToggle }: WaterfallRowProps) {
  const statusClass = span.status.code === 2 ? "error" : span.status.code === 1 ? "ok" : "unset";
  const barMinWidth = Math.max(span.durationPercent, 0.5);

  return (
    <div
      className={`waterfall__row ${isSelected ? "waterfall__row--selected" : ""}`}
      onClick={onSelect}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onSelect(); } }}
    >
      <div className="waterfall__row-service" style={{ paddingLeft: `${12 + span.depth * 20}px` }}>
        {hasChildren ? (
          <button
            className="waterfall__toggle"
            onClick={(e) => { e.stopPropagation(); onToggle(); }}
            aria-label={isCollapsed ? "Expand" : "Collapse"}
          >
            {isCollapsed ? "▶" : "▼"}
          </button>
        ) : (
          <span className="waterfall__toggle-spacer" />
        )}
        <span className="waterfall__service-name">{span.resource.serviceName}</span>
        <span className="waterfall__span-name">{span.name}</span>
      </div>
      <div className="waterfall__row-timeline">
        <div
          className={`waterfall__bar waterfall__bar--${statusClass}`}
          style={{
            left: `${span.offsetPercent}%`,
            width: `${barMinWidth}%`,
          }}
        >
          <span className="waterfall__bar-label">{formatDurationMs(span.durationMs)}</span>
        </div>
      </div>
    </div>
  );
}

function getVisibleSpans(spans: WaterfallSpan[], collapsed: Set<string>): WaterfallSpan[] {
  const result: WaterfallSpan[] = [];
  const hiddenParents = new Set<string>();

  for (const span of spans) {
    if (hiddenParents.has(span.parentSpanId)) {
      hiddenParents.add(span.spanId);
      continue;
    }
    result.push(span);
    if (collapsed.has(span.spanId)) {
      hiddenParents.add(span.spanId);
    }
  }
  return result;
}
