import { useMemo, useRef, useState } from "react";
import type { MetricSeries } from "./useMetricTimeSeries";

type TimeSeriesChartProps = {
  series: MetricSeries[];
  displayType: "lines" | "bars" | "area";
  unit: string;
  selectedSeriesKey: string | null;
  onSelectSeries: (key: string | null) => void;
};

const COLORS = [
  "#4fc1ff", "#89d185", "#dcdcaa", "#c586c0", "#f48771",
  "#ce9178", "#9cdcfe", "#b5cea8", "#d4d4d4", "#569cd6",
];

const MARGIN = { top: 12, right: 16, bottom: 32, left: 56 };

export function TimeSeriesChart({ series, displayType, unit, selectedSeriesKey, onSelectSeries }: TimeSeriesChartProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [hover, setHover] = useState<{ x: number; y: number; ts: number; seriesIdx: number; values: { key: string; label: string; value: number; color: string }[] } | null>(null);

  const chart = useMemo(() => {
    if (series.length === 0) return null;

    const allTs = new Set<number>();
    for (const s of series) {
      for (const p of s.points) allTs.add(p.ts);
    }
    const timestamps = Array.from(allTs).sort((a, b) => a - b);
    if (timestamps.length < 2) return null;

    const aligned: { ts: number; values: (number | null)[] }[] = timestamps.map((ts) => ({
      ts,
      values: series.map((s) => {
        let closest: number | null = null;
        for (const p of s.points) {
          if (p.ts <= ts) closest = p.value;
        }
        return closest;
      }),
    }));

    let minVal = Infinity;
    let maxVal = -Infinity;
    for (const row of aligned) {
      for (const v of row.values) {
        if (v !== null) {
          if (v < minVal) minVal = v;
          if (v > maxVal) maxVal = v;
        }
      }
    }
    if (!isFinite(minVal)) { minVal = 0; maxVal = 1; }
    const valRange = maxVal - minVal || 1;
    minVal = Math.max(0, minVal - valRange * 0.05);
    maxVal = maxVal + valRange * 0.1;

    const tsMin = timestamps[0];
    const tsMax = timestamps[timestamps.length - 1];
    const tsRange = tsMax - tsMin || 1;

    return { aligned, timestamps, minVal, maxVal, tsMin, tsMax, tsRange, valRange: maxVal - minVal };
  }, [series]);

  if (!chart || series.length === 0) {
    return (
      <div className="ts-chart ts-chart--empty">
        <p>Select a metric to view its time-series chart.</p>
        <p className="ts-chart__hint">Data accumulates as the demo app sends OTLP updates.</p>
      </div>
    );
  }

  const width = 800;
  const height = 300;
  const innerW = width - MARGIN.left - MARGIN.right;
  const innerH = height - MARGIN.top - MARGIN.bottom;

  const xScale = (ts: number) => MARGIN.left + ((ts - chart.tsMin) / chart.tsRange) * innerW;
  const yScale = (val: number) => MARGIN.top + innerH - ((val - chart.minVal) / chart.valRange) * innerH;

  const yTickCount = 5;
  const yTicks: number[] = [];
  for (let i = 0; i <= yTickCount; i++) {
    yTicks.push(chart.minVal + (chart.valRange * i) / yTickCount);
  }

  const xTickCount = Math.min(6, chart.timestamps.length);
  const xTicks: number[] = [];
  for (let i = 0; i < xTickCount; i++) {
    const idx = Math.floor((i / (xTickCount - 1)) * (chart.timestamps.length - 1));
    xTicks.push(chart.timestamps[idx]);
  }

  function handleMouseMove(e: React.MouseEvent<SVGSVGElement>) {
    if (!chart) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const mx = ((e.clientX - rect.left) / rect.width) * width;
    const my = e.clientY - rect.top;

    const tsFrac = (mx - MARGIN.left) / innerW;
    if (tsFrac < 0 || tsFrac > 1) { setHover(null); return; }
    const tsTarget = chart.tsMin + tsFrac * chart.tsRange;

    let nearestIdx = 0;
    let nearestDist = Infinity;
    for (let i = 0; i < chart.aligned.length; i++) {
      const d = Math.abs(chart.aligned[i].ts - tsTarget);
      if (d < nearestDist) { nearestDist = d; nearestIdx = i; }
    }

    const row = chart.aligned[nearestIdx];

    // Find closest series to mouse Y
    const myScaled = ((e.clientY - rect.top) / rect.height) * height;
    let closestSeries = 0;
    let closestDist = Infinity;
    for (let si = 0; si < series.length; si++) {
      const v = row.values[si];
      if (v !== null) {
        const sy = yScale(v);
        const d = Math.abs(myScaled - sy);
        if (d < closestDist) { closestDist = d; closestSeries = si; }
      }
    }

    const values = series.map((s, i) => ({
      key: s.key,
      label: seriesLabel(s),
      value: row.values[i] ?? 0,
      color: COLORS[i % COLORS.length],
    }));

    setHover({ x: xScale(row.ts), y: my, ts: row.ts, seriesIdx: closestSeries, values });
  }

  function handleClick() {
    if (!hover) return;
    const s = series[hover.seriesIdx];
    if (s) {
      onSelectSeries(selectedSeriesKey === s.key ? null : s.key);
    }
  }

  const hasSelection = selectedSeriesKey !== null;

  return (
    <div className="ts-chart" ref={containerRef}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="ts-chart__svg"
        onMouseMove={handleMouseMove}
        onMouseLeave={() => setHover(null)}
        onClick={handleClick}
        style={{ cursor: "crosshair" }}
      >
        {/* Grid lines */}
        {yTicks.map((v, i) => (
          <line
            key={`yg-${i}`}
            x1={MARGIN.left} x2={width - MARGIN.right}
            y1={yScale(v)} y2={yScale(v)}
            stroke="rgba(255,255,255,0.06)" strokeWidth={1}
          />
        ))}

        {/* Y-axis labels */}
        {yTicks.map((v, i) => (
          <text key={`yt-${i}`} x={MARGIN.left - 8} y={yScale(v) + 4}
            textAnchor="end" className="ts-chart__axis-label">
            {formatValue(v)}
          </text>
        ))}

        {/* X-axis labels */}
        {xTicks.map((ts, i) => (
          <text key={`xt-${i}`} x={xScale(ts)} y={height - 8}
            textAnchor="middle" className="ts-chart__axis-label">
            {formatTime(ts)}
          </text>
        ))}

        {/* Series */}
        {series.map((s, si) => {
          const color = COLORS[si % COLORS.length];
          const isSelected = s.key === selectedSeriesKey;
          const isDimmed = hasSelection && !isSelected;
          const opacity = isDimmed ? 0.15 : 1;
          const strokeW = isSelected ? 2.5 : 1.5;

          const points = chart.aligned
            .map((row) => ({ ts: row.ts, value: row.values[si] }))
            .filter((p) => p.value !== null) as { ts: number; value: number }[];

          if (points.length < 2) return null;

          if (displayType === "bars") {
            const barW = Math.max(2, (innerW / chart.aligned.length) * 0.6 / series.length);
            return (
              <g key={`s-${si}`} opacity={opacity}>
                {points.map((p, pi) => (
                  <rect
                    key={`bar-${si}-${pi}`}
                    x={xScale(p.ts) - barW / 2 + si * (barW + 1)}
                    y={yScale(p.value)}
                    width={barW}
                    height={Math.max(1, yScale(chart.minVal) - yScale(p.value))}
                    fill={color} opacity={0.7} rx={1}
                  />
                ))}
              </g>
            );
          }

          const linePath = points.map((p, i) =>
            `${i === 0 ? "M" : "L"} ${xScale(p.ts)} ${yScale(p.value)}`
          ).join(" ");

          if (displayType === "area") {
            const areaPath = linePath +
              ` L ${xScale(points[points.length - 1].ts)} ${yScale(chart.minVal)}` +
              ` L ${xScale(points[0].ts)} ${yScale(chart.minVal)} Z`;
            return (
              <g key={`s-${si}`} opacity={opacity}>
                <path d={areaPath} fill={color} opacity={0.12} />
                <path d={linePath} fill="none" stroke={color} strokeWidth={strokeW} />
              </g>
            );
          }

          return (
            <g key={`s-${si}`} opacity={opacity}>
              <path d={linePath} fill="none" stroke={color} strokeWidth={strokeW} />
              {(isSelected || (!hasSelection && points.length <= 50)) ? points.map((p, pi) => (
                <circle key={pi} cx={xScale(p.ts)} cy={yScale(p.value)} r={isSelected ? 3 : 2} fill={color} />
              )) : null}
            </g>
          );
        })}

        {/* Hover crosshair */}
        {hover ? (
          <line
            x1={hover.x} x2={hover.x}
            y1={MARGIN.top} y2={height - MARGIN.bottom}
            stroke="rgba(255,255,255,0.3)" strokeWidth={1} strokeDasharray="3,3"
          />
        ) : null}
      </svg>

      {/* Hover tooltip */}
      {hover ? (
        <div className="ts-chart__tooltip" style={{ left: Math.min(hover.x, width - 180), top: MARGIN.top }}>
          <div className="ts-chart__tooltip-time">{new Date(hover.ts).toLocaleTimeString()}</div>
          {hover.values.map((v, i) => (
            <div key={i} className={`ts-chart__tooltip-row ${i === hover.seriesIdx ? "ts-chart__tooltip-row--highlight" : ""}`}>
              <span className="ts-chart__tooltip-dot" style={{ background: v.color }} />
              <span className="ts-chart__tooltip-label">{v.label}</span>
              <span className="ts-chart__tooltip-value">{formatValue(v.value)}</span>
            </div>
          ))}
        </div>
      ) : null}

      {/* Annotation: compact clickable series labels */}
      <div className="ts-chart__annotations">
        {series.map((s, i) => {
          const isSelected = s.key === selectedSeriesKey;
          return (
            <button
              key={s.key}
              className={`ts-chart__annotation ${isSelected ? "ts-chart__annotation--active" : ""} ${hasSelection && !isSelected ? "ts-chart__annotation--dimmed" : ""}`}
              onClick={(e) => { e.stopPropagation(); onSelectSeries(isSelected ? null : s.key); }}
              type="button"
              title={`Click to ${isSelected ? "deselect" : "select and filter by dimensions"}`}
            >
              <span className="ts-chart__annotation-dot" style={{ background: COLORS[i % COLORS.length] }} />
              <span className="ts-chart__annotation-label">{seriesLabel(s)}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

function seriesLabel(s: MetricSeries): string {
  const attrs = Object.entries(s.attributes);
  if (attrs.length === 0) return s.metricName;
  const parts = attrs.slice(0, 3).map(([k, v]) => `${k}:${v}`).join(", ");
  return attrs.length > 3 ? `${parts}, ...` : parts;
}

function formatValue(v: number): string {
  if (Math.abs(v) >= 1_000_000) return `${(v / 1_000_000).toFixed(1)}M`;
  if (Math.abs(v) >= 1_000) return `${(v / 1_000).toFixed(1)}K`;
  if (Number.isInteger(v)) return v.toLocaleString();
  return v.toFixed(2);
}

function formatTime(ts: number): string {
  const d = new Date(ts);
  return d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}
