import { useState, useMemo, useRef } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { getStringAttributeValue, type LogsRequest, type TelemetryAttribute } from "../telemetry/types";
import { ExplorerLayout, FacetSidebar, SearchBar, DetailPanel } from "../layout";
import type { FacetGroup } from "../layout/types";

type LogsTabProps = {
  logs: LogsRequest;
  onInteract?: () => void;
};

type LogRecord = {
  body: string;
  service: string;
  severity: string;
  timestamp: string;
  attributes: Record<string, string>;
  index: number;
};

function severityClass(sev: string): string {
  const s = sev.toUpperCase();
  if (s.includes("ERROR") || s.includes("FATAL")) return "error";
  if (s.includes("WARN")) return "warn";
  if (s.includes("INFO")) return "info";
  if (s.includes("DEBUG") || s.includes("TRACE")) return "debug";
  return "default";
}

export function LogsTab({ logs, onInteract }: LogsTabProps) {
  const [search, setSearch] = useState("");
  const [facetSelection, setFacetSelection] = useState<Record<string, Set<string>>>({});
  const [selectedIndex, setSelectedIndex] = useState<number | null>(null);
  const tableRef = useRef<HTMLDivElement>(null);
  const searchRef = useRef<HTMLInputElement>(null);

  const logRecords: LogRecord[] = useMemo(() => {
    let idx = 0;
    return logs.resourceLogs.flatMap((rl) =>
      rl.scopeLogs.flatMap((sl) =>
        sl.logRecords.map((lr) => ({
          body:
            getStringAttributeValue({ key: "body", value: { value: lr.body?.value } }) ??
            "Structured payload",
          service: getStringAttr(rl.resource?.attributes, "service.name") ?? "unknown",
          severity: lr.severityText || "UNSPECIFIED",
          timestamp: lr.timeUnixNano || lr.observedTimeUnixNano || "0",
          attributes: extractAttrs(lr.attributes),
          index: idx++,
        })),
      ),
    );
  }, [logs]);

  const facets = useMemo(() => extractLogFacets(logRecords), [logRecords]);

  const filtered = useMemo(() => {
    const svc = facetSelection["service"];
    const sev = facetSelection["severity"];
    const q = search.toLowerCase().trim();
    return logRecords.filter((r) => {
      if (svc?.size && !svc.has(r.service)) return false;
      if (sev?.size && !sev.has(r.severity)) return false;
      if (q && !r.body.toLowerCase().includes(q) && !r.service.toLowerCase().includes(q)) return false;
      return true;
    });
  }, [logRecords, facetSelection, search]);

  const selectedLog = selectedIndex !== null ? logRecords[selectedIndex] ?? null : null;

  function handleToggleFacet(groupKey: string, value: string) {
    setFacetSelection((prev) => {
      const next = { ...prev };
      const set = new Set(prev[groupKey] ?? []);
      set.has(value) ? set.delete(value) : set.add(value);
      if (set.size === 0) delete next[groupKey];
      else next[groupKey] = set;
      return next;
    });
  }

  const virtualizer = useVirtualizer({
    count: filtered.length,
    getScrollElement: () => tableRef.current,
    estimateSize: () => 36,
    overscan: 10,
  });

  const sidebar = (
    <FacetSidebar groups={facets} selected={facetSelection} onToggle={handleToggleFacet} />
  );

  const panel = selectedLog ? (
    <DetailPanel
      title={selectedLog.severity}
      subtitle={selectedLog.service}
      onClose={() => setSelectedIndex(null)}
    >
      <div className="log-detail">
        <div className="log-detail__section">
          <h4 className="log-detail__heading">Message</h4>
          <pre className="log-detail__body">{selectedLog.body}</pre>
        </div>
        <div className="log-detail__section">
          <h4 className="log-detail__heading">Attributes</h4>
          {Object.entries(selectedLog.attributes).length > 0 ? (
            <table className="log-detail__attrs">
              <tbody>
                {Object.entries(selectedLog.attributes).map(([k, v]) => (
                  <tr key={k}>
                    <td className="log-detail__attr-key">{k}</td>
                    <td className="log-detail__attr-val">{v}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p className="log-detail__empty">No attributes</p>
          )}
        </div>
      </div>
    </DetailPanel>
  ) : undefined;

  return (
    <section className="tab-panel" role="tabpanel">
      <ExplorerLayout sidebar={sidebar} panel={panel}>
        <SearchBar
          value={search}
          onChange={setSearch}
          placeholder="Search logs..."
          inputRef={searchRef}
          activeFacets={Object.keys(facetSelection).length > 0 ? facetSelection : undefined}
          onClearFacet={handleToggleFacet}
        />

        <div className="explorer__toolbar">
          <span className="explorer__count">
            {filtered.length === logRecords.length
              ? `${logRecords.length} logs`
              : `${filtered.length} of ${logRecords.length} logs`}
          </span>
        </div>

        {logRecords.length === 0 ? (
          <p className="explorer__status">Waiting for logs... Send OTLP data to port 4318.</p>
        ) : null}

        <div className="data-table__head data-table__head--logs">
          <span className="data-table__th data-table__th--severity">Level</span>
          <span className="data-table__th data-table__th--timestamp">Timestamp</span>
          <span className="data-table__th data-table__th--service">Service</span>
          <span className="data-table__th data-table__th--message">Message</span>
        </div>

        <div className="data-table__body" ref={tableRef}>
          <div style={{ height: virtualizer.getTotalSize(), position: "relative" }}>
            {virtualizer.getVirtualItems().map((vi) => {
              const r = filtered[vi.index];
              const active = r.index === selectedIndex;
              const cls = severityClass(r.severity);
              return (
                <button
                  key={vi.index}
                  className={`data-table__row data-table__row--logs data-table__row--sev-${cls} ${active ? "data-table__row--active" : ""}`}
                  onClick={() => { setSelectedIndex(r.index); onInteract?.(); }}
                  type="button"
                  style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    width: "100%",
                    transform: `translateY(${vi.start}px)`,
                  }}
                  data-index={vi.index}
                  ref={virtualizer.measureElement}
                >
                  <span className={`data-table__td data-table__td--severity sev-badge sev-badge--${cls}`}>
                    {r.severity}
                  </span>
                  <span className="data-table__td data-table__td--timestamp">
                    {formatNano(r.timestamp)}
                  </span>
                  <span className="data-table__td data-table__td--service">{r.service}</span>
                  <span className="data-table__td data-table__td--message">{r.body}</span>
                </button>
              );
            })}
          </div>
        </div>
      </ExplorerLayout>
    </section>
  );
}

// --- helpers ---

function getStringAttr(
  attrs: ReadonlyArray<TelemetryAttribute> | undefined,
  key: string,
): string | undefined {
  const a = attrs?.find((e) => e.key === key);
  return getStringAttributeValue(a);
}

function extractAttrs(attrs?: ReadonlyArray<TelemetryAttribute>): Record<string, string> {
  if (!attrs) return {};
  const out: Record<string, string> = {};
  for (const a of attrs) {
    const v = getStringAttributeValue(a);
    if (v !== undefined) out[a.key] = v;
  }
  return out;
}

function extractLogFacets(records: LogRecord[]): FacetGroup[] {
  const services = new Map<string, number>();
  const severities = new Map<string, number>();
  for (const r of records) {
    services.set(r.service, (services.get(r.service) ?? 0) + 1);
    severities.set(r.severity, (severities.get(r.severity) ?? 0) + 1);
  }
  return [
    {
      key: "severity",
      label: "Severity",
      values: [...severities.entries()]
        .sort((a, b) => b[1] - a[1])
        .map(([value, count]) => ({ value, count })),
    },
    {
      key: "service",
      label: "Service",
      values: [...services.entries()]
        .sort((a, b) => b[1] - a[1])
        .map(([value, count]) => ({ value, count })),
    },
  ].filter((g) => g.values.length > 0);
}

function formatNano(nano: string): string {
  const ms = Number(BigInt(nano) / 1_000_000n);
  if (isNaN(ms) || ms === 0) return "--";
  const d = new Date(ms);
  return d.toISOString().slice(11, 23);
}
