import { useState, useMemo } from "react";
import { TimeSeriesChart } from "./TimeSeriesChart";
import { useMetricTimeSeries } from "./useMetricTimeSeries";
import type { MetricSeries } from "./useMetricTimeSeries";
import type { MetricsRequest } from "../telemetry/types";

type MetricsTabProps = {
  metrics: MetricsRequest;
  telemetryError: string | null;
};

type DisplayType = "lines" | "bars" | "area";

export function MetricsTab({ metrics, telemetryError }: MetricsTabProps) {
  const [selectedMetric, setSelectedMetric] = useState<string | null>(null);
  const [selectedSeriesKey, setSelectedSeriesKey] = useState<string | null>(null);
  const [displayType, setDisplayType] = useState<DisplayType>("lines");
  const [search, setSearch] = useState("");

  const { allSeries, metricList } = useMetricTimeSeries(metrics);

  const filteredMetrics = useMemo(() => {
    const q = search.toLowerCase().trim();
    if (!q) return metricList;
    return metricList.filter(
      (m) => m.name.toLowerCase().includes(q) || m.description.toLowerCase().includes(q),
    );
  }, [metricList, search]);

  const activeMetric = selectedMetric ?? filteredMetrics[0]?.name ?? null;

  const chartSeries = useMemo(() => {
    if (!activeMetric) return [];
    return allSeries.filter((s) => s.metricName === activeMetric);
  }, [allSeries, activeMetric]);

  const activeInfo = metricList.find((m) => m.name === activeMetric);
  const selectedSeries = selectedSeriesKey ? chartSeries.find((s) => s.key === selectedSeriesKey) ?? null : null;

  function handleSelectMetric(name: string) {
    setSelectedMetric(name);
    setSelectedSeriesKey(null); // clear series selection on metric change
  }

  return (
    <section className="tab-panel" role="tabpanel">
      <div className="metrics-explorer">
        {/* Left: Metric list */}
        <div className="metrics-explorer__sidebar">
          <div className="metrics-explorer__search">
            <input
              className="metrics-explorer__search-input"
              type="text"
              placeholder="Filter metrics..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <div className="metrics-explorer__list">
            {filteredMetrics.map((m) => (
              <button
                key={m.name}
                className={`metrics-explorer__item ${m.name === activeMetric ? "metrics-explorer__item--active" : ""}`}
                onClick={() => handleSelectMetric(m.name)}
                type="button"
              >
                <span className={`metrics-explorer__item-type metric-type--${m.type}`}>
                  {typeGlyph(m.type)}
                </span>
                <span className="metrics-explorer__item-info">
                  <span className="metrics-explorer__item-name">{m.name}</span>
                  {m.description ? (
                    <span className="metrics-explorer__item-desc">{m.description}</span>
                  ) : null}
                </span>
                <span className="metrics-explorer__item-badge">
                  {m.seriesCount}
                </span>
              </button>
            ))}
            {filteredMetrics.length === 0 ? (
              <p className="metrics-explorer__empty">
                {metricList.length === 0
                  ? "Waiting for metrics..."
                  : "No metrics match your search."}
              </p>
            ) : null}
          </div>
        </div>

        {/* Right: Query bar + Chart + Dimensions */}
        <div className="metrics-explorer__main">
          {/* Query bar */}
          <div className="metrics-explorer__query-bar">
            <div className="metrics-explorer__query-row">
              <span className="metrics-explorer__query-label">Metric</span>
              <span className="metrics-explorer__query-value">
                {activeMetric ?? "none"}
              </span>
              {activeInfo ? (
                <>
                  <span className="metrics-explorer__query-sep">/</span>
                  <span className={`metrics-explorer__query-type metric-type--${activeInfo.type}`}>
                    {activeInfo.type}
                  </span>
                  {activeInfo.unit ? (
                    <>
                      <span className="metrics-explorer__query-sep">/</span>
                      <span className="metrics-explorer__query-unit">{activeInfo.unit}</span>
                    </>
                  ) : null}
                  <span className="metrics-explorer__query-sep">/</span>
                  <span className="metrics-explorer__query-series">
                    {chartSeries.length} series
                  </span>
                </>
              ) : null}
            </div>
          </div>

          {/* Display controls */}
          <div className="metrics-explorer__controls">
            <div className="metrics-explorer__display">
              <span className="metrics-explorer__control-label">Display:</span>
              <div className="view-toggle">
                <button
                  className={`view-toggle__btn ${displayType === "lines" ? "view-toggle__btn--active" : ""}`}
                  onClick={() => setDisplayType("lines")}
                  type="button"
                >
                  Lines
                </button>
                <button
                  className={`view-toggle__btn ${displayType === "bars" ? "view-toggle__btn--active" : ""}`}
                  onClick={() => setDisplayType("bars")}
                  type="button"
                >
                  Bars
                </button>
                <button
                  className={`view-toggle__btn ${displayType === "area" ? "view-toggle__btn--active" : ""}`}
                  onClick={() => setDisplayType("area")}
                  type="button"
                >
                  Area
                </button>
              </div>
            </div>
          </div>

          {telemetryError ? (
            <p className="explorer__status explorer__status--error">{telemetryError}</p>
          ) : null}

          {/* Chart */}
          <div className="metrics-explorer__chart">
            {activeMetric ? (
              <>
                <div className="metrics-explorer__chart-title">
                  {activeMetric}
                  {activeInfo?.unit ? <span className="metrics-explorer__chart-unit">({activeInfo.unit})</span> : null}
                </div>
                <TimeSeriesChart
                  series={chartSeries}
                  displayType={displayType}
                  unit={activeInfo?.unit ?? ""}
                  selectedSeriesKey={selectedSeriesKey}
                  onSelectSeries={setSelectedSeriesKey}
                />
              </>
            ) : (
              <div className="ts-chart ts-chart--empty">
                <p>Select a metric from the list to view its time-series chart.</p>
              </div>
            )}
          </div>

          {/* Series detail panel: shown when a series is selected */}
          {selectedSeries ? (
            <SeriesDetailPanel series={selectedSeries} onClose={() => setSelectedSeriesKey(null)} />
          ) : null}
        </div>
      </div>
    </section>
  );
}

function SeriesDetailPanel({ series, onClose }: { series: MetricSeries; onClose: () => void }) {
  const stats = useMemo(() => computeStats(series), [series]);
  const dimEntries = Object.entries(series.attributes);
  const [showResource, setShowResource] = useState(false);

  const resourceEntries = useMemo(() => {
    return Object.entries(series.resource)
      .filter(([k]) => !RESOURCE_HIDDEN.has(k))
      .sort(([a], [b]) => {
        const ai = RESOURCE_PRIORITY.indexOf(a);
        const bi = RESOURCE_PRIORITY.indexOf(b);
        if (ai !== -1 && bi !== -1) return ai - bi;
        if (ai !== -1) return -1;
        if (bi !== -1) return 1;
        return a.localeCompare(b);
      });
  }, [series.resource]);

  return (
    <div className="series-detail">
      {/* Header */}
      <div className="series-detail__header">
        <span className="series-detail__title">{series.metricName}</span>
        <button className="series-detail__close" onClick={onClose} type="button" aria-label="Close">&times;</button>
      </div>

      {/* Stat strip */}
      <div className="series-detail__stats">
        {[
          ["Latest", series.latest],
          ["Min", stats.min],
          ["Max", stats.max],
          ["Avg", stats.avg],
          ["Pts", series.points.length],
        ].map(([label, value]) => (
          <div key={label as string} className="stat-card">
            <span className="stat-card__label">{label as string}</span>
            <span className="stat-card__value">{typeof value === "number" ? fmtNum(value) : value}</span>
          </div>
        ))}
      </div>

      {/* Type + metadata pills */}
      <div className="series-detail__tags">
        <span className={`series-detail__tag series-detail__tag--type metric-type--${series.type}`}>{series.type}</span>
        {series.unit ? <span className="series-detail__tag">{series.unit}</span> : null}
        {series.temporality ? <span className="series-detail__tag">{series.temporality}</span> : null}
        {series.monotonic === "true" ? <span className="series-detail__tag">monotonic</span> : null}
      </div>

      {series.description ? <p className="series-detail__desc">{series.description}</p> : null}

      {/* Dimensions as tag pills (Datadog style) */}
      {dimEntries.length > 0 ? (
        <div className="series-detail__section">
          <div className="series-detail__section-title">Tags</div>
          <div className="series-detail__tags">
            {dimEntries.map(([key, value]) => (
              <span key={key} className="series-detail__dim-tag" title={`${key}: ${value}`}>
                <span className="series-detail__dim-key">{key}:</span>{value}
              </span>
            ))}
          </div>
        </div>
      ) : null}

      {/* Scope */}
      {series.scope.name ? (
        <div className="series-detail__section">
          <div className="series-detail__section-title">Instrumentation</div>
          <span className="series-detail__tag">
            {series.scope.name}{series.scope.version ? ` ${series.scope.version}` : ""}
          </span>
        </div>
      ) : null}

      {/* Resource — collapsible */}
      {resourceEntries.length > 0 ? (
        <div className="series-detail__section">
          <button
            className="series-detail__section-toggle"
            onClick={() => setShowResource((v) => !v)}
            type="button"
          >
            <span className="series-detail__section-title">Resource ({resourceEntries.length})</span>
            <span className="series-detail__chevron">{showResource ? "\u25B4" : "\u25BE"}</span>
          </button>
          {showResource ? (
            <table className="kv-table">
              <tbody>
                {resourceEntries.map(([key, value]) => (
                  <tr key={key} className="kv-table__row">
                    <td className="kv-table__key">{key}</td>
                    <td className="kv-table__val" title={value}>{truncateValue(value)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : null}
        </div>
      ) : null}
    </div>
  );
}

/** Resource attributes to hide — noisy, low-value for metric analysis. */
const RESOURCE_HIDDEN = new Set([
  "process.command_args",
  "process.executable.path",
  "process.executable.name",
  "process.pid",
  "process.runtime.description",
  "process.runtime.name",
  "process.runtime.version",
  "process.command",
  "process.owner",
]);

/** Sort resource attributes: important ones first, then alphabetical. */
const RESOURCE_PRIORITY = [
  "service.name", "service.version", "deployment.environment.name",
  "host.name", "host.arch", "host.id",
  "telemetry.sdk.language", "telemetry.sdk.name", "telemetry.sdk.version",
];

function truncateValue(value: string, max = 80): string {
  if (value.length <= max) return value;
  return value.slice(0, max) + "\u2026";
}

function computeStats(series: MetricSeries): { min: number; max: number; avg: number } {
  const pts = series.points;
  if (pts.length === 0) return { min: 0, max: 0, avg: 0 };
  let min = Infinity;
  let max = -Infinity;
  let sum = 0;
  for (const p of pts) {
    if (p.value < min) min = p.value;
    if (p.value > max) max = p.value;
    sum += p.value;
  }
  return { min, max, avg: sum / pts.length };
}

function fmtNum(v: number): string {
  if (Math.abs(v) >= 1_000_000) return `${(v / 1_000_000).toFixed(2)}M`;
  if (Math.abs(v) >= 1_000) return `${(v / 1_000).toFixed(2)}K`;
  if (Number.isInteger(v)) return v.toLocaleString();
  return v.toFixed(3);
}

function typeGlyph(type: string): string {
  switch (type) {
    case "counter": return "\u2191";
    case "gauge": return "\u25CC";
    case "histogram": return "\u25EB";
    case "summary": return "\u2726";
    default: return "\u2022";
  }
}
