import { useEffect, useRef, useState } from "react";
import type { MetricsRequest, TelemetryAttribute } from "../telemetry/types";

/** A single point on the chart: wall-clock time + value. */
export type TimeSeriesPoint = {
  /** Unix ms when this sample was recorded. */
  ts: number;
  value: number;
};

/** One series = one metric + one set of attribute values. */
export type MetricSeries = {
  /** Unique key: metricName + sorted attribute kv pairs. */
  key: string;
  metricName: string;
  attributes: Record<string, string>;
  points: TimeSeriesPoint[];
  latest: number;
  type: "counter" | "gauge" | "histogram" | "summary";
  unit: string;
  description: string;
  /** Context from the OTLP resource/scope/metric. */
  resource: Record<string, string>;
  scope: { name: string; version: string };
  temporality?: string;
  monotonic?: string;
};

/** Summary info about a distinct metric name. */
export type MetricInfo = {
  name: string;
  type: "counter" | "gauge" | "histogram" | "summary";
  unit: string;
  description: string;
  seriesCount: number;
  service: string;
};

const MAX_POINTS = 300; // ~5 min at 1s intervals

/**
 * Accumulates OTLP metric snapshots into time-series data suitable for charting.
 * Each WebSocket update adds one sample per series.
 */
export function useMetricTimeSeries(metrics: MetricsRequest) {
  const seriesMapRef = useRef(new Map<string, MetricSeries>());
  const [version, setVersion] = useState(0);

  useEffect(() => {
    const now = Date.now();
    const map = seriesMapRef.current;

    for (const rm of metrics.resourceMetrics) {
      const service = getServiceName(rm.resource?.attributes);
      const resourceAttrs = flattenTelemetryAttrs(rm.resource?.attributes);
      for (const sm of rm.scopeMetrics) {
        const scopeInfo = {
          name: sm.scope?.name ?? "",
          version: sm.scope?.version ?? "",
        };
        for (const metric of sm.metrics) {
          const { metricType, dataPoints, temporality, monotonic } = extractDataPoints(metric);

          for (const dp of dataPoints) {
            const attrStr = serializeAttrs(dp.attributes);
            const key = `${metric.name}|${attrStr}`;

            let series = map.get(key);
            if (!series) {
              series = {
                key,
                metricName: metric.name,
                attributes: flattenAttrs(dp.attributes),
                points: [],
                latest: dp.value,
                type: metricType,
                unit: metric.unit,
                description: metric.description,
                resource: resourceAttrs,
                scope: scopeInfo,
                temporality,
                monotonic,
              };
              map.set(key, series);
            }

            // Use the data point's timeUnixNano if available, else wall-clock
            const pointTs = dp.timeUnixNano
              ? Number(BigInt(dp.timeUnixNano) / 1_000_000n)
              : now;

            // Avoid duplicate timestamps (same export cycle)
            const lastPoint = series.points[series.points.length - 1];
            if (!lastPoint || lastPoint.ts !== pointTs) {
              series.points.push({ ts: pointTs, value: dp.value });
              if (series.points.length > MAX_POINTS) {
                series.points.shift();
              }
            } else {
              // Update value at same timestamp
              lastPoint.value = dp.value;
            }

            series.latest = dp.value;
          }
        }
      }
    }

    setVersion((v) => v + 1);
  }, [metrics]);

  // Build the metrics list + series from the ref (triggered by version)
  const seriesMap = seriesMapRef.current;

  const allSeries: MetricSeries[] = Array.from(seriesMap.values());

  // Group by metric name
  const metricNames = new Map<string, MetricInfo>();
  for (const rm of metrics.resourceMetrics) {
    const service = getServiceName(rm.resource?.attributes);
    for (const sm of rm.scopeMetrics) {
      for (const metric of sm.metrics) {
        const { metricType } = extractDataPoints(metric);
        const existing = metricNames.get(metric.name);
        const seriesCount = allSeries.filter((s) => s.metricName === metric.name).length;
        if (!existing || seriesCount > existing.seriesCount) {
          metricNames.set(metric.name, {
            name: metric.name,
            type: metricType,
            unit: metric.unit,
            description: metric.description,
            seriesCount,
            service,
          });
        }
      }
    }
  }

  const metricList: MetricInfo[] = Array.from(metricNames.values()).sort((a, b) =>
    a.name.localeCompare(b.name),
  );

  return { allSeries, metricList, version };
}

// --- internals ---

type ExtractedPoint = {
  attributes: TelemetryAttribute[];
  value: number;
  timeUnixNano?: string;
};

type ExtractedResult = {
  metricType: MetricSeries["type"];
  dataPoints: ExtractedPoint[];
  temporality?: string;
  monotonic?: string;
};

function temporalityLabel(val: number | undefined): string | undefined {
  if (val === 1) return "delta";
  if (val === 2) return "cumulative";
  return undefined;
}

function extractDataPoints(metric: MetricsRequest["resourceMetrics"][0]["scopeMetrics"][0]["metrics"][0]): ExtractedResult {
  const data = metric.data as any;
  if (!data) return { metricType: "gauge", dataPoints: [] };

  if (data.gauge) {
    return {
      metricType: "gauge",
      dataPoints: (data.gauge.dataPoints ?? []).map((dp: any) => ({
        attributes: dp.attributes ?? [],
        value: extractNumberValue(dp),
        timeUnixNano: dp.timeUnixNano,
      })),
    };
  }

  if (data.sum) {
    return {
      metricType: "counter",
      dataPoints: (data.sum.dataPoints ?? []).map((dp: any) => ({
        attributes: dp.attributes ?? [],
        value: extractNumberValue(dp),
        timeUnixNano: dp.timeUnixNano,
      })),
      temporality: temporalityLabel(data.sum.aggregationTemporality),
      monotonic: data.sum.isMonotonic != null ? String(data.sum.isMonotonic) : undefined,
    };
  }

  if (data.histogram) {
    return {
      metricType: "histogram",
      dataPoints: (data.histogram.dataPoints ?? []).map((dp: any) => ({
        attributes: dp.attributes ?? [],
        value: dp.count > 0 && dp.sum != null ? dp.sum / Number(dp.count) : 0,
        timeUnixNano: dp.timeUnixNano,
      })),
      temporality: temporalityLabel(data.histogram.aggregationTemporality),
    };
  }

  if (data.exponentialHistogram) {
    return {
      metricType: "histogram",
      dataPoints: (data.exponentialHistogram.dataPoints ?? []).map((dp: any) => ({
        attributes: dp.attributes ?? [],
        value: dp.count > 0 && dp.sum != null ? dp.sum / Number(dp.count) : 0,
        timeUnixNano: dp.timeUnixNano,
      })),
      temporality: temporalityLabel(data.exponentialHistogram.aggregationTemporality),
    };
  }

  if (data.summary) {
    return {
      metricType: "summary",
      dataPoints: (data.summary.dataPoints ?? []).map((dp: any) => ({
        attributes: dp.attributes ?? [],
        value: dp.count > 0 ? dp.sum / Number(dp.count) : 0,
        timeUnixNano: dp.timeUnixNano,
      })),
    };
  }

  // Fallback: check $case format (protobuf oneof)
  const $case = data.$case;
  if ($case && data[$case]) {
    const inner = data[$case];
    const dps = inner.dataPoints ?? [];
    const type: MetricSeries["type"] =
      $case === "sum" ? "counter" :
      $case === "histogram" || $case === "exponentialHistogram" ? "histogram" :
      $case === "summary" ? "summary" : "gauge";
    return {
      metricType: type,
      dataPoints: dps.map((dp: any) => ({
        attributes: dp.attributes ?? [],
        value: extractNumberValue(dp),
        timeUnixNano: dp.timeUnixNano,
      })),
      temporality: temporalityLabel(inner.aggregationTemporality),
      monotonic: inner.isMonotonic != null ? String(inner.isMonotonic) : undefined,
    };
  }

  return { metricType: "gauge", dataPoints: [] };
}

function extractNumberValue(dp: any): number {
  if (dp.value != null) {
    if (typeof dp.value === "number") return dp.value;
    if (dp.value.$case === "asDouble") return dp.value.asDouble;
    if (dp.value.$case === "asInt") return Number(dp.value.asInt);
  }
  if (typeof dp.sum === "number" && dp.count) {
    const count = Number(dp.count);
    return count > 0 ? dp.sum / count : 0;
  }
  if (typeof dp.sum === "number") return dp.sum;
  if (dp.count != null) return Number(dp.count);
  return 0;
}

function serializeAttrs(attrs: TelemetryAttribute[]): string {
  return attrs
    .map((a) => `${a.key}=${getAttrValue(a)}`)
    .sort()
    .join(",");
}

function flattenAttrs(attrs: TelemetryAttribute[]): Record<string, string> {
  const out: Record<string, string> = {};
  for (const a of attrs) {
    out[a.key] = getAttrValue(a);
  }
  return out;
}

function getAttrValue(attr: TelemetryAttribute): string {
  const v = attr.value?.value;
  if (!v) return "";
  if (v.$case === "stringValue" && "stringValue" in v) return v.stringValue;
  if (v.$case === "intValue" && "intValue" in v) return v.intValue;
  if (v.$case === "doubleValue" && "doubleValue" in v) return String(v.doubleValue);
  if (v.$case === "boolValue" && "boolValue" in v) return String(v.boolValue);
  return JSON.stringify(v);
}

function flattenTelemetryAttrs(attrs: TelemetryAttribute[] | undefined): Record<string, string> {
  const out: Record<string, string> = {};
  if (!attrs) return out;
  for (const a of attrs) {
    out[a.key] = getAttrValue(a);
  }
  return out;
}

function getServiceName(attrs: TelemetryAttribute[] | undefined): string {
  const a = attrs?.find((a) => a.key === "service.name");
  return getAttrValue(a ?? { key: "" }) || "unknown";
}
