import type { RefObject } from "react";
import type { WaterfallTrace } from "./waterfall-layout";

export type TraceFilters = {
  serviceName: string;
  spanName: string;
  status: string;
  minDurationMs: string;
  maxDurationMs: string;
  traceIdPrefix: string;
};

export const emptyFilters: TraceFilters = {
  serviceName: "",
  spanName: "",
  status: "",
  minDurationMs: "",
  maxDurationMs: "",
  traceIdPrefix: "",
};

type TraceFilterBarProps = {
  filters: TraceFilters;
  filterInputRef?: RefObject<HTMLInputElement | null>;
  onChange: (filters: TraceFilters) => void;
  traces: WaterfallTrace[];
};

export function TraceFilterBar({ filters, filterInputRef, onChange, traces }: TraceFilterBarProps) {
  const services = [...new Set(traces.map((t) => t.serviceName).filter(Boolean))].sort();

  function update(key: keyof TraceFilters, value: string) {
    onChange({ ...filters, [key]: value });
  }

  const hasFilters = Object.values(filters).some((v) => v !== "");

  return (
    <div className="filter-bar">
      <div className="filter-bar__group">
        <label className="filter-bar__label">
          Service
          <select
            className="filter-bar__select"
            value={filters.serviceName}
            onChange={(e) => update("serviceName", e.target.value)}
          >
            <option value="">All</option>
            {services.map((s) => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </label>

        <label className="filter-bar__label">
          Span name
          <input
            ref={filterInputRef}
            className="filter-bar__input"
            type="text"
            placeholder="Filter by span name..."
            value={filters.spanName}
            onChange={(e) => update("spanName", e.target.value)}
          />
        </label>

        <label className="filter-bar__label">
          Status
          <select
            className="filter-bar__select"
            value={filters.status}
            onChange={(e) => update("status", e.target.value)}
          >
            <option value="">All</option>
            <option value="ok">OK</option>
            <option value="error">Error</option>
            <option value="mixed">Mixed</option>
            <option value="unset">Unset</option>
          </select>
        </label>

        <label className="filter-bar__label">
          Min duration (ms)
          <input
            className="filter-bar__input filter-bar__input--small"
            type="number"
            placeholder="0"
            value={filters.minDurationMs}
            onChange={(e) => update("minDurationMs", e.target.value)}
          />
        </label>

        <label className="filter-bar__label">
          Max duration (ms)
          <input
            className="filter-bar__input filter-bar__input--small"
            type="number"
            placeholder="∞"
            value={filters.maxDurationMs}
            onChange={(e) => update("maxDurationMs", e.target.value)}
          />
        </label>

        <label className="filter-bar__label">
          Trace ID
          <input
            className="filter-bar__input"
            type="text"
            placeholder="Trace ID prefix..."
            value={filters.traceIdPrefix}
            onChange={(e) => update("traceIdPrefix", e.target.value)}
          />
        </label>
      </div>

      {hasFilters ? (
        <button className="filter-bar__clear" onClick={() => onChange(emptyFilters)}>
          Clear filters
        </button>
      ) : null}
    </div>
  );
}

export function applyTraceFilters(traces: WaterfallTrace[], filters: TraceFilters): WaterfallTrace[] {
  return traces.filter((trace) => {
    if (filters.serviceName && trace.serviceName.toLowerCase() !== filters.serviceName.toLowerCase()) return false;
    if (filters.status && trace.status !== filters.status) return false;
    if (filters.traceIdPrefix && !trace.traceId.toLowerCase().startsWith(filters.traceIdPrefix.toLowerCase())) return false;
    if (filters.spanName) {
      const search = filters.spanName.toLowerCase();
      if (!trace.spans.some((s) => s.name.toLowerCase().includes(search))) return false;
    }
    if (filters.minDurationMs) {
      const min = parseFloat(filters.minDurationMs);
      if (!isNaN(min) && (trace.durationMs === null || trace.durationMs < min)) return false;
    }
    if (filters.maxDurationMs) {
      const max = parseFloat(filters.maxDurationMs);
      if (!isNaN(max) && (trace.durationMs === null || trace.durationMs > max)) return false;
    }
    return true;
  });
}
