import { type WaterfallTrace, formatDurationMs } from "./waterfall-layout";
import { TraceWaterfall } from "./TraceWaterfall";
import { useState } from "react";

type TraceComparisonProps = {
  traceA: WaterfallTrace;
  traceB: WaterfallTrace;
  onClose: () => void;
};

export function TraceComparison({ traceA, traceB, onClose }: TraceComparisonProps) {
  const [selectedSpanA, setSelectedSpanA] = useState<string | null>(null);
  const [selectedSpanB, setSelectedSpanB] = useState<string | null>(null);
  const [collapsedA, setCollapsedA] = useState<Set<string>>(new Set());
  const [collapsedB, setCollapsedB] = useState<Set<string>>(new Set());

  function toggleCollapse(set: Set<string>, setter: (s: Set<string>) => void, spanId: string) {
    const next = new Set(set);
    if (next.has(spanId)) next.delete(spanId); else next.add(spanId);
    setter(next);
  }

  const durationDiff = traceA.durationMs !== null && traceB.durationMs !== null
    ? traceB.durationMs - traceA.durationMs
    : null;

  const spanDiff = traceB.spanCount - traceA.spanCount;

  return (
    <div className="trace-comparison">
      <div className="trace-comparison__header">
        <h3 className="trace-comparison__title">Trace Comparison</h3>
        <div className="trace-comparison__summary">
          {durationDiff !== null ? (
            <span className={`trace-comparison__diff ${durationDiff > 0 ? "trace-comparison__diff--slower" : "trace-comparison__diff--faster"}`}>
              {durationDiff > 0 ? "+" : ""}{durationDiff.toFixed(2)}ms
            </span>
          ) : null}
          {spanDiff !== 0 ? (
            <span className="trace-comparison__diff">
              {spanDiff > 0 ? "+" : ""}{spanDiff} spans
            </span>
          ) : null}
        </div>
        <button className="span-details__close" onClick={onClose} aria-label="Close comparison">×</button>
      </div>

      <div className="trace-comparison__panels">
        <div className="trace-comparison__panel">
          <div className="trace-comparison__panel-label">
            <span className="trace-summary__id">{traceA.traceId}</span>
            <span className="trace-summary__duration">{formatDurationMs(traceA.durationMs)}</span>
            <span className="trace-summary__spans">{traceA.spanCount} spans</span>
          </div>
          <TraceWaterfall
            trace={traceA}
            selectedSpanId={selectedSpanA}
            onSelectSpan={setSelectedSpanA}
            collapsedSpans={collapsedA}
            onToggleCollapse={(id) => toggleCollapse(collapsedA, setCollapsedA, id)}
          />
        </div>

        <div className="trace-comparison__panel">
          <div className="trace-comparison__panel-label">
            <span className="trace-summary__id">{traceB.traceId}</span>
            <span className="trace-summary__duration">{formatDurationMs(traceB.durationMs)}</span>
            <span className="trace-summary__spans">{traceB.spanCount} spans</span>
          </div>
          <TraceWaterfall
            trace={traceB}
            selectedSpanId={selectedSpanB}
            onSelectSpan={setSelectedSpanB}
            collapsedSpans={collapsedB}
            onToggleCollapse={(id) => toggleCollapse(collapsedB, setCollapsedB, id)}
          />
        </div>
      </div>
    </div>
  );
}
