import type { TelemetryAttribute } from "../telemetry/types";

export type WaterfallSpan = {
  attributes: TelemetryAttribute[];
  children: WaterfallSpan[];
  depth: number;
  durationMs: number | null;
  durationPercent: number;
  endTimeUnixNano: string;
  events: Array<{ name: string; timeUnixNano: string; attributes: TelemetryAttribute[] }>;
  kind: string;
  links: Array<{ traceId: string; spanId: string; attributes: TelemetryAttribute[] }>;
  name: string;
  offsetPercent: number;
  parentSpanId: string;
  resource: { serviceName: string; attributes: TelemetryAttribute[] };
  scope: { name: string; version: string };
  spanId: string;
  startTimeUnixNano: string;
  status: { code: number; message: string };
  traceId: string;
};

export type WaterfallTrace = {
  durationMs: number | null;
  rootSpanName: string;
  serviceName: string;
  spanCount: number;
  spans: WaterfallSpan[];
  status: "error" | "mixed" | "ok" | "unset";
  traceId: string;
};

export function buildWaterfallTrace(
  resourceSpans: any,
): WaterfallTrace {
  const flatSpans: WaterfallSpan[] = [];
  const traceId = getFirstTraceId(resourceSpans);
  const serviceName = getServiceName(resourceSpans.resource?.attributes);

  for (const scopeSpans of resourceSpans.scopeSpans ?? []) {
    for (const span of scopeSpans.spans ?? []) {
      flatSpans.push({
        attributes: span.attributes ?? [],
        children: [],
        depth: 0,
        durationMs: computeDurationMs(span.startTimeUnixNano, span.endTimeUnixNano),
        durationPercent: 0,
        endTimeUnixNano: span.endTimeUnixNano ?? "",
        events: (span.events ?? []).map((e: any) => ({
          name: e.name ?? "",
          timeUnixNano: e.timeUnixNano ?? "",
          attributes: e.attributes ?? [],
        })),
        kind: formatSpanKind(span.kind),
        links: (span.links ?? []).map((l: any) => ({
          traceId: toHex(l.traceId),
          spanId: toHex(l.spanId),
          attributes: l.attributes ?? [],
        })),
        name: span.name || "unnamed",
        offsetPercent: 0,
        parentSpanId: toHex(span.parentSpanId),
        resource: { serviceName, attributes: resourceSpans.resource?.attributes ?? [] },
        scope: {
          name: scopeSpans.scope?.name ?? "",
          version: scopeSpans.scope?.version ?? "",
        },
        spanId: toHex(span.spanId),
        startTimeUnixNano: span.startTimeUnixNano ?? "",
        status: {
          code: span.status?.code ?? 0,
          message: span.status?.message ?? "",
        },
        traceId: toHex(span.traceId ?? new Uint8Array()),
      });
    }
  }

  // Build tree
  const spanById = new Map(flatSpans.map((s) => [s.spanId, s]));
  const roots: WaterfallSpan[] = [];
  for (const span of flatSpans) {
    if (span.parentSpanId === "" || !spanById.has(span.parentSpanId)) {
      roots.push(span);
    } else {
      spanById.get(span.parentSpanId)!.children.push(span);
    }
  }

  // Sort children by start time
  const sortByStart = (a: WaterfallSpan, b: WaterfallSpan) =>
    compareNano(a.startTimeUnixNano, b.startTimeUnixNano);
  roots.sort(sortByStart);
  for (const span of flatSpans) {
    span.children.sort(sortByStart);
  }

  // Flatten into display order with depth
  const ordered: WaterfallSpan[] = [];
  const visited = new Set<string>();

  function walk(span: WaterfallSpan, depth: number) {
    if (visited.has(span.spanId)) return;
    visited.add(span.spanId);
    span.depth = depth;
    ordered.push(span);
    for (const child of span.children) {
      walk(child, depth + 1);
    }
  }

  for (const root of roots) walk(root, 0);
  // Add any orphans not visited
  for (const span of flatSpans) {
    if (!visited.has(span.spanId)) {
      span.depth = 0;
      ordered.push(span);
    }
  }

  // Compute time offsets
  const traceStart = getTraceStartNano(ordered);
  const traceEnd = getTraceEndNano(ordered);
  const traceDurationNs = traceStart !== null && traceEnd !== null ? Number(traceEnd - traceStart) : 0;
  const traceDurationMs = traceDurationNs > 0 ? traceDurationNs / 1_000_000 : null;

  for (const span of ordered) {
    if (traceDurationNs > 0 && traceStart !== null) {
      const startNs = parseNano(span.startTimeUnixNano);
      const endNs = parseNano(span.endTimeUnixNano);
      if (startNs !== null) {
        span.offsetPercent = (Number(startNs - traceStart) / traceDurationNs) * 100;
      }
      if (startNs !== null && endNs !== null) {
        span.durationPercent = (Number(endNs - startNs) / traceDurationNs) * 100;
      }
    }
  }

  const rootSpan = ordered.find((s) => s.parentSpanId === "") ?? ordered[0];

  return {
    durationMs: traceDurationMs,
    rootSpanName: rootSpan?.name ?? "",
    serviceName,
    spanCount: ordered.length,
    spans: ordered,
    status: getTraceStatus(ordered),
    traceId,
  };
}

function getTraceStatus(spans: WaterfallSpan[]): "error" | "mixed" | "ok" | "unset" {
  const codes = new Set(spans.map((s) => s.status.code));
  if (codes.has(2)) return codes.size === 1 ? "error" : "mixed";
  if (codes.has(1)) return codes.size === 1 ? "ok" : "mixed";
  return "unset";
}

function getTraceStartNano(spans: WaterfallSpan[]): bigint | null {
  let min: bigint | null = null;
  for (const s of spans) {
    const n = parseNano(s.startTimeUnixNano);
    if (n !== null && (min === null || n < min)) min = n;
  }
  return min;
}

function getTraceEndNano(spans: WaterfallSpan[]): bigint | null {
  let max: bigint | null = null;
  for (const s of spans) {
    const n = parseNano(s.endTimeUnixNano);
    if (n !== null && (max === null || n > max)) max = n;
  }
  return max;
}

function parseNano(value: string): bigint | null {
  if (!value || value.trim() === "") return null;
  try { return BigInt(value); } catch { return null; }
}

function compareNano(a: string, b: string): number {
  const an = parseNano(a);
  const bn = parseNano(b);
  if (an !== null && bn !== null) return an < bn ? -1 : an > bn ? 1 : 0;
  if (an !== null) return -1;
  if (bn !== null) return 1;
  return 0;
}

function computeDurationMs(start: string, end: string): number | null {
  const s = parseNano(start);
  const e = parseNano(end);
  if (s === null || e === null || e < s) return null;
  return Number(e - s) / 1_000_000;
}

function toHex(value: Uint8Array | undefined): string {
  if (!value || value.length === 0) return "";
  return Array.from(value, (b) => b.toString(16).padStart(2, "0")).join("");
}

function formatSpanKind(kind: number | undefined): string {
  switch (kind) {
    case 1: return "internal";
    case 2: return "server";
    case 3: return "client";
    case 4: return "producer";
    case 5: return "consumer";
    default: return "unspecified";
  }
}

function getFirstTraceId(resourceSpans: any): string {
  for (const ss of resourceSpans.scopeSpans ?? []) {
    for (const span of ss.spans ?? []) {
      if (span.traceId) return toHex(span.traceId).slice(0, 16);
    }
  }
  return "";
}

function getServiceName(attributes: TelemetryAttribute[] | undefined): string {
  const attr = attributes?.find((a) => a.key === "service.name");
  const v = attr?.value?.value;
  if (v && "$case" in v && v.$case === "stringValue" && "stringValue" in v) {
    return (v as any).stringValue;
  }
  return "unknown";
}

export function formatDurationMs(ms: number | null): string {
  if (ms === null) return "--";
  if (ms < 1) return `${(ms * 1000).toFixed(0)}μs`;
  if (ms < 1000) return `${ms.toFixed(2)}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}
