import { useCallback, useEffect, useRef, useState } from "react";
import { ExportLogsServiceRequest as LogsRequestCodec } from "./otlp-codecs.js";
import { ExportMetricsServiceRequest as MetricsRequestCodec } from "./otlp-codecs.js";
import { ExportTraceServiceRequest as TracesRequestCodec } from "./otlp-codecs.js";
import type { LogsRequest, MetricsRequest, TelemetryWebSocketMessage, TracesRequest } from "./types";

export type TelemetryState = {
  error: string | null;
  logs: LogsRequest;
  metrics: MetricsRequest;
  traces: TracesRequest;
};

export type TelemetryHandle = {
  /** The telemetry data currently visible to the UI. */
  state: TelemetryState;
  /** Whether updates are paused (buffered but not applied). */
  paused: boolean;
  /** Number of WebSocket updates received while paused. */
  pendingUpdates: number;
  /** Pause live updates — incoming data is buffered silently. */
  pause: () => void;
  /** Resume and apply the latest buffered state. */
  resume: () => void;
  /** Toggle pause/resume. */
  toggle: () => void;
  /** Flush any buffered data into the visible state while staying paused. */
  flush: () => void;
};

const emptyTelemetryState: TelemetryState = {
  error: null,
  logs: { resourceLogs: [] },
  metrics: { resourceMetrics: [] },
  traces: { resourceSpans: [] },
};

export function useTelemetry(): TelemetryHandle {
  const [telemetry, setTelemetry] = useState<TelemetryState>(emptyTelemetryState);
  const [paused, setPaused] = useState(false);
  const [pendingUpdates, setPendingUpdates] = useState(0);

  // Refs so the WebSocket callback always sees current pause state
  // without needing to re-create the effect.
  const pausedRef = useRef(paused);
  pausedRef.current = paused;

  // Buffer: holds the latest telemetry state received while paused.
  const bufferRef = useRef<TelemetryState | null>(null);

  useEffect(() => {
    let isActive = true;
    let reconnectTimer: number | null = null;
    let socket: WebSocket | null = null;

    const connect = () => {
      socket = new WebSocket(`${window.location.protocol === "https:" ? "wss" : "ws"}://${window.location.host}/api/telemetry`);

      socket.addEventListener("message", (event) => {
        if (!isActive) {
          return;
        }

        try {
          const message = JSON.parse(event.data) as TelemetryWebSocketMessage;
          const payload = decodeBase64(message.payloadBase64);

          const apply = (current: TelemetryState): TelemetryState => {
            switch (message.signal) {
              case "logs":
                return { ...current, error: null, logs: LogsRequestCodec.decode(payload) as LogsRequest };
              case "metrics":
                return { ...current, error: null, metrics: MetricsRequestCodec.decode(payload) as MetricsRequest };
              case "traces":
                return { ...current, error: null, traces: TracesRequestCodec.decode(payload) as TracesRequest };
              default:
                return current;
            }
          };

          if (pausedRef.current) {
            // Buffer the update without touching visible state.
            const base = bufferRef.current ?? telemetryRef.current;
            bufferRef.current = apply(base);
            setPendingUpdates((n) => n + 1);
          } else {
            setTelemetry(apply);
          }
        } catch {
          setTelemetry((current) => ({ ...current, error: "Received invalid telemetry WebSocket payload." }));
        }
      });

      socket.addEventListener("close", () => {
        if (!isActive) {
          return;
        }

        reconnectTimer = window.setTimeout(connect, 1000);
      });

      socket.addEventListener("error", () => {
        socket?.close();
      });
    };

    connect();

    return () => {
      isActive = false;
      if (reconnectTimer !== null) {
        window.clearTimeout(reconnectTimer);
      }
      socket?.close();
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Keep a ref to current telemetry so the WS callback can use it as
  // a base when buffering (avoids stale closure over `telemetry`).
  const telemetryRef = useRef(telemetry);
  telemetryRef.current = telemetry;

  const flush = useCallback(() => {
    if (bufferRef.current) {
      setTelemetry(bufferRef.current);
      bufferRef.current = null;
    }
    setPendingUpdates(0);
  }, []);

  const pause = useCallback(() => {
    if (pausedRef.current) {
      // Already paused — flush buffered data so the user sees the latest
      // rows while staying paused (e.g. clicking another row).
      flush();
      return;
    }
    setPaused(true);
    bufferRef.current = null;
    setPendingUpdates(0);
  }, [flush]);

  const resume = useCallback(() => {
    setPaused(false);
    if (bufferRef.current) {
      setTelemetry(bufferRef.current);
    }
    bufferRef.current = null;
    setPendingUpdates(0);
  }, []);

  const toggle = useCallback(() => {
    if (pausedRef.current) {
      resume();
    } else {
      pause();
    }
  }, [pause, resume]);

  return { state: telemetry, paused, pendingUpdates, pause, resume, toggle, flush };
}

function decodeBase64(value: string): Uint8Array {
  const binary = window.atob(value);
  const bytes = new Uint8Array(binary.length);

  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index);
  }

  return bytes;
}
