import { useState } from "react";
import { getAttributeDisplayInfo, type TelemetryAttribute } from "../telemetry/types";
import { type WaterfallSpan, formatDurationMs } from "./waterfall-layout";

type SpanDetailsPanelProps = {
  span: WaterfallSpan;
  onClose: () => void;
};

export function SpanDetailsPanel({ span, onClose }: SpanDetailsPanelProps) {
  const [copiedField, setCopiedField] = useState<string | null>(null);

  function copyToClipboard(value: string, field: string) {
    navigator.clipboard.writeText(value).then(() => {
      setCopiedField(field);
      setTimeout(() => setCopiedField(null), 1500);
    });
  }

  const statusLabel = span.status.code === 2 ? "ERROR" : span.status.code === 1 ? "OK" : "UNSET";
  const statusClass = span.status.code === 2 ? "error" : span.status.code === 1 ? "ok" : "unset";

  return (
    <aside className="span-details" role="complementary" aria-label="Span details">
      <div className="span-details__header">
        <div className="span-details__title">
          <h3 className="span-details__name">{span.name}</h3>
          <div className="span-details__meta">
            <span className="span-details__service">{span.resource.serviceName}</span>
            <span className="span-details__duration">{formatDurationMs(span.durationMs)}</span>
            <span className={`trace-status trace-status--${statusClass}`}>{statusLabel}</span>
          </div>
        </div>
        <button className="span-details__close" onClick={onClose} aria-label="Close details">×</button>
      </div>

      <div className="span-details__body">
        <DetailsSection title="Span Information" defaultOpen>
          <DetailRow label="Trace ID" value={span.traceId} onCopy={() => copyToClipboard(span.traceId, "traceId")} copied={copiedField === "traceId"} />
          <DetailRow label="Span ID" value={span.spanId} onCopy={() => copyToClipboard(span.spanId, "spanId")} copied={copiedField === "spanId"} />
          <DetailRow label="Parent Span ID" value={span.parentSpanId || "(root)"} />
          <DetailRow label="Kind" value={span.kind} />
          <DetailRow label="Duration" value={formatDurationMs(span.durationMs)} />
          <DetailRow label="Start" value={span.startTimeUnixNano} />
          <DetailRow label="End" value={span.endTimeUnixNano} />
          {span.status.message ? <DetailRow label="Status Message" value={span.status.message} /> : null}
        </DetailsSection>

        <DetailsSection title={`Attributes (${span.attributes.length})`} defaultOpen={span.attributes.length <= 20}>
          {span.attributes.length === 0 ? (
            <p className="span-details__empty">No attributes</p>
          ) : (
            <div className="span-details__attrs">
              {span.attributes.map((attr) => {
                const display = getAttributeDisplayInfo(attr);
                return (
                  <div key={attr.key} className="span-details__attr-row">
                    <span className="span-details__attr-key">{attr.key}</span>
                    <span className={`span-details__attr-value attribute-pill__value--${display.type}`}>{display.value}</span>
                  </div>
                );
              })}
            </div>
          )}
        </DetailsSection>

        {span.events.length > 0 ? (
          <DetailsSection title={`Events (${span.events.length})`} defaultOpen>
            {span.events.map((event, i) => (
              <div key={`${event.name}-${i}`} className="span-details__event">
                <span className="span-details__event-name">{event.name}</span>
                <span className="span-details__event-time">{event.timeUnixNano}</span>
                {event.attributes.length > 0 ? (
                  <div className="span-details__event-attrs">
                    {event.attributes.map((attr) => {
                      const display = getAttributeDisplayInfo(attr);
                      return (
                        <span key={attr.key} className="attribute-pill">
                          <span className="attribute-pill__key">{attr.key}</span>=
                          <span className={`attribute-pill__value attribute-pill__value--${display.type}`}>{display.value}</span>
                        </span>
                      );
                    })}
                  </div>
                ) : null}
              </div>
            ))}
          </DetailsSection>
        ) : null}

        {span.links.length > 0 ? (
          <DetailsSection title={`Links (${span.links.length})`} defaultOpen>
            {span.links.map((link, i) => (
              <div key={`${link.traceId}-${link.spanId}-${i}`} className="span-details__link">
                <span className="span-details__link-label">Trace: {link.traceId}</span>
                <span className="span-details__link-label">Span: {link.spanId}</span>
              </div>
            ))}
          </DetailsSection>
        ) : null}

        <DetailsSection title="Resource" defaultOpen={false}>
          <ResourceAttributes attributes={span.resource.attributes} />
        </DetailsSection>

        <DetailsSection title="Scope" defaultOpen={false}>
          <DetailRow label="Name" value={span.scope.name || "(empty)"} />
          <DetailRow label="Version" value={span.scope.version || "(empty)"} />
        </DetailsSection>
      </div>
    </aside>
  );
}

function DetailsSection({ title, defaultOpen = true, children }: { title: string; defaultOpen?: boolean; children: React.ReactNode }) {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="span-details__section">
      <button
        className="span-details__section-header"
        onClick={() => setIsOpen(!isOpen)}
        aria-expanded={isOpen}
      >
        <span className="span-details__section-toggle">{isOpen ? "▼" : "▶"}</span>
        <span>{title}</span>
      </button>
      {isOpen ? <div className="span-details__section-body">{children}</div> : null}
    </div>
  );
}

function DetailRow({ label, value, onCopy, copied }: { label: string; value: string; onCopy?: () => void; copied?: boolean }) {
  return (
    <div className="span-details__detail-row">
      <span className="span-details__detail-label">{label}</span>
      <span className="span-details__detail-value">
        {value}
        {onCopy ? (
          <button className="span-details__copy-btn" onClick={onCopy} aria-label={`Copy ${label}`}>
            {copied ? "Copied" : "Copy"}
          </button>
        ) : null}
      </span>
    </div>
  );
}

function ResourceAttributes({ attributes }: { attributes: TelemetryAttribute[] }) {
  if (attributes.length === 0) return <p className="span-details__empty">No resource attributes</p>;
  return (
    <div className="span-details__attrs">
      {attributes.map((attr) => {
        const display = getAttributeDisplayInfo(attr);
        return (
          <div key={attr.key} className="span-details__attr-row">
            <span className="span-details__attr-key">{attr.key}</span>
            <span className={`span-details__attr-value attribute-pill__value--${display.type}`}>{display.value}</span>
          </div>
        );
      })}
    </div>
  );
}
