import type { ReactNode } from "react";

type DetailPanelProps = {
  title: string;
  subtitle?: string;
  onClose: () => void;
  children: ReactNode;
};

export function DetailPanel({ title, subtitle, onClose, children }: DetailPanelProps) {
  return (
    <div className="detail-panel">
      <div className="detail-panel__header">
        <div className="detail-panel__titles">
          <h3 className="detail-panel__title">{title}</h3>
          {subtitle ? <span className="detail-panel__subtitle">{subtitle}</span> : null}
        </div>
        <button className="detail-panel__close" onClick={onClose} aria-label="Close panel">
          &times;
        </button>
      </div>
      <div className="detail-panel__body">{children}</div>
    </div>
  );
}
