/**
 * Component map — aggregates span relationships across traces into a graph.
 *
 * Nodes represent operations (SERVER spans) or backends (CLIENT span targets).
 * Edges represent calls between them, with aggregated stats.
 */
import type { WaterfallTrace, WaterfallSpan } from "./waterfall-layout";
import { getStringAttributeValue, type TelemetryAttribute } from "../telemetry/types";

// ── Types ────────────────────────────────────────────────

export type NodeKind = "service" | "database" | "cache" | "http" | "messaging";

export type GraphNode = {
  id: string;
  label: string;
  sublabel: string;
  kind: NodeKind;
  calls: number;
  errors: number;
  avgDurationMs: number;
  // Laid-out position (set by layoutGraph)
  x: number;
  y: number;
};

export type GraphEdge = {
  sourceId: string;
  targetId: string;
  calls: number;
  errors: number;
  avgDurationMs: number;
};

export type ComponentGraph = {
  nodes: GraphNode[];
  edges: GraphEdge[];
  width: number;
  height: number;
  /** Reverse index: node ID → set of trace IDs that contain this node */
  nodeTraces: Map<string, Set<string>>;
  /** Reverse index: edge key (source→target) → set of trace IDs that traverse this edge */
  edgeTraces: Map<string, Set<string>>;
};

// ── Extraction ───────────────────────────────────────────

function getAttr(attrs: TelemetryAttribute[], key: string): string | undefined {
  return getStringAttributeValue(attrs.find((a) => a.key === key));
}

function classifyBackend(span: WaterfallSpan): { kind: NodeKind; id: string; label: string; sublabel: string } {
  const dbSystem = getAttr(span.attributes, "db.system.name");
  if (dbSystem) {
    const server = getAttr(span.attributes, "server.address") ?? dbSystem;
    const isCache = dbSystem === "redis" || dbSystem === "memcached";
    return {
      kind: isCache ? "cache" : "database",
      id: `db:${dbSystem}:${server}`,
      label: dbSystem,
      sublabel: server,
    };
  }

  const rpcService = getAttr(span.attributes, "rpc.service");
  if (rpcService) {
    const server = getAttr(span.attributes, "server.address") ?? rpcService;
    return { kind: "http", id: `rpc:${rpcService}`, label: rpcService, sublabel: server };
  }

  const msgSystem = getAttr(span.attributes, "messaging.system");
  if (msgSystem) {
    const dest = getAttr(span.attributes, "messaging.destination.name") ?? msgSystem;
    return { kind: "messaging", id: `msg:${msgSystem}:${dest}`, label: msgSystem, sublabel: dest };
  }

  const httpMethod = getAttr(span.attributes, "http.request.method");
  const serverAddr = getAttr(span.attributes, "server.address");
  if (httpMethod && serverAddr) {
    return { kind: "http", id: `http:${serverAddr}`, label: serverAddr, sublabel: httpMethod };
  }

  return { kind: "http", id: `ext:${span.name}`, label: span.name, sublabel: "" };
}

/**
 * Walk a span tree to find parent→child call edges.
 * Records which traceId each node/edge belongs to for filtering.
 */
function walkSpan(
  span: WaterfallSpan,
  parentNodeId: string | null,
  traceId: string,
  nodeStats: Map<string, { kind: NodeKind; label: string; sublabel: string; durations: number[]; errors: number }>,
  edgeStats: Map<string, { calls: number; errors: number; durations: number[] }>,
  nodeTraces: Map<string, Set<string>>,
  edgeTraces: Map<string, Set<string>>,
) {
  let nodeId: string | null = null;

  if (span.kind === "server") {
    // Server span = an operation node
    const route = getAttr(span.attributes, "http.route") ?? span.name;
    const method = getAttr(span.attributes, "http.request.method") ?? "";
    nodeId = `svc:${span.resource.serviceName}:${route}`;
    const existing = nodeStats.get(nodeId);
    const dur = span.durationMs ?? 0;
    const isError = span.status.code === 2;
    if (existing) {
      existing.durations.push(dur);
      if (isError) existing.errors++;
    } else {
      nodeStats.set(nodeId, {
        kind: "service",
        label: method ? `${method} ${route}` : route,
        sublabel: span.resource.serviceName,
        durations: [dur],
        errors: isError ? 1 : 0,
      });
    }
    // Track trace membership
    if (!nodeTraces.has(nodeId)) nodeTraces.set(nodeId, new Set());
    nodeTraces.get(nodeId)!.add(traceId);
  } else if (span.kind === "client") {
    // Client span = call to a backend
    const backend = classifyBackend(span);
    nodeId = backend.id;
    const existing = nodeStats.get(nodeId);
    const dur = span.durationMs ?? 0;
    const isError = span.status.code === 2;
    if (existing) {
      existing.durations.push(dur);
      if (isError) existing.errors++;
    } else {
      nodeStats.set(nodeId, {
        kind: backend.kind,
        label: backend.label,
        sublabel: backend.sublabel,
        durations: [dur],
        errors: isError ? 1 : 0,
      });
    }
    // Track trace membership
    if (!nodeTraces.has(nodeId)) nodeTraces.set(nodeId, new Set());
    nodeTraces.get(nodeId)!.add(traceId);

    // Create edge from parent service to this backend
    if (parentNodeId) {
      const edgeKey = `${parentNodeId}→${nodeId}`;
      const existingEdge = edgeStats.get(edgeKey);
      if (existingEdge) {
        existingEdge.calls++;
        existingEdge.durations.push(dur);
        if (isError) existingEdge.errors++;
      } else {
        edgeStats.set(edgeKey, { calls: 1, errors: isError ? 1 : 0, durations: [dur] });
      }
      // Track edge trace membership
      if (!edgeTraces.has(edgeKey)) edgeTraces.set(edgeKey, new Set());
      edgeTraces.get(edgeKey)!.add(traceId);
    }
  }

  // The "owner" for children is the most recent service/server node
  const ownerForChildren = nodeId && (span.kind === "server" || span.kind === "internal")
    ? nodeId
    : parentNodeId;

  // For internal spans, if there's no nodeId yet, try to find the nearest server parent
  const effectiveOwner = span.kind === "internal" ? (parentNodeId ?? nodeId) : ownerForChildren;

  for (const child of span.children) {
    walkSpan(child, effectiveOwner ?? parentNodeId, traceId, nodeStats, edgeStats, nodeTraces, edgeTraces);
  }
}

export function buildComponentGraph(traces: WaterfallTrace[]): ComponentGraph {
  const nodeStats = new Map<string, { kind: NodeKind; label: string; sublabel: string; durations: number[]; errors: number }>();
  const edgeStats = new Map<string, { calls: number; errors: number; durations: number[] }>();
  const nodeTraces = new Map<string, Set<string>>();
  const edgeTraces = new Map<string, Set<string>>();

  for (const trace of traces) {
    // Find root spans (parentSpanId is empty or not in this trace)
    const spanIds = new Set(trace.spans.map((s) => s.spanId));
    const roots = trace.spans.filter((s) => s.parentSpanId === "" || !spanIds.has(s.parentSpanId));
    for (const root of roots) {
      walkSpan(root, null, trace.traceId, nodeStats, edgeStats, nodeTraces, edgeTraces);
    }
  }

  // Build nodes
  const nodes: GraphNode[] = [];
  for (const [id, stats] of nodeStats) {
    const totalDur = stats.durations.reduce((a, b) => a + b, 0);
    nodes.push({
      id,
      label: stats.label,
      sublabel: stats.sublabel,
      kind: stats.kind,
      calls: stats.durations.length,
      errors: stats.errors,
      avgDurationMs: stats.durations.length > 0 ? totalDur / stats.durations.length : 0,
      x: 0,
      y: 0,
    });
  }

  // Build edges
  const edges: GraphEdge[] = [];
  for (const [key, stats] of edgeStats) {
    const [sourceId, targetId] = key.split("→");
    const totalDur = stats.durations.reduce((a, b) => a + b, 0);
    edges.push({
      sourceId,
      targetId,
      calls: stats.calls,
      errors: stats.errors,
      avgDurationMs: stats.durations.length > 0 ? totalDur / stats.durations.length : 0,
    });
  }

  return layoutGraph(nodes, edges, nodeTraces, edgeTraces);
}

// ── Layout ───────────────────────────────────────────────

/**
 * Simple layered layout: service nodes on the left, backend nodes on the right.
 * Within each column, nodes are sorted by call count (most calls at top).
 */
function layoutGraph(
  nodes: GraphNode[],
  edges: GraphEdge[],
  nodeTraces: Map<string, Set<string>>,
  edgeTraces: Map<string, Set<string>>,
): ComponentGraph {
  const NODE_W = 200;
  const NODE_H = 80;
  const COL_GAP = 280;
  const ROW_GAP = 32;
  const PAD = 40;

  // Separate service nodes (sources) from backend nodes (targets)
  const targetIds = new Set(edges.map((e) => e.targetId));
  const sourceIds = new Set(edges.map((e) => e.sourceId));

  const serviceNodes = nodes.filter((n) => n.kind === "service");
  const backendNodes = nodes.filter((n) => n.kind !== "service");
  // Nodes that are neither source nor target — orphans go to services column
  const orphanServices = serviceNodes.filter((n) => !sourceIds.has(n.id) && !targetIds.has(n.id));

  // Sort by calls descending
  serviceNodes.sort((a, b) => b.calls - a.calls);
  backendNodes.sort((a, b) => b.calls - a.calls);

  // Lay out service column (left)
  let y = PAD;
  for (const node of serviceNodes) {
    node.x = PAD;
    node.y = y;
    y += NODE_H + ROW_GAP;
  }

  // Lay out backend column (right)
  y = PAD;
  for (const node of backendNodes) {
    node.x = PAD + NODE_W + COL_GAP;
    node.y = y;
    y += NODE_H + ROW_GAP;
  }

  const maxServiceY = serviceNodes.length > 0 ? serviceNodes[serviceNodes.length - 1].y + NODE_H : PAD;
  const maxBackendY = backendNodes.length > 0 ? backendNodes[backendNodes.length - 1].y + NODE_H : PAD;

  return {
    nodes,
    edges,
    width: PAD * 2 + NODE_W * 2 + COL_GAP,
    height: Math.max(maxServiceY, maxBackendY) + PAD,
    nodeTraces,
    edgeTraces,
  };
}

// ── Constants for rendering ──────────────────────────────

export const NODE_WIDTH = 200;
export const NODE_HEIGHT = 80;
