import { useRef, type RefObject } from "react";

type SearchBarProps = {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  inputRef?: RefObject<HTMLInputElement | null>;
  activeFacets?: Record<string, Set<string>>;
  onClearFacet?: (key: string, value: string) => void;
};

export function SearchBar({
  value,
  onChange,
  placeholder = "Search or filter...",
  inputRef,
  activeFacets,
  onClearFacet,
}: SearchBarProps) {
  const fallbackRef = useRef<HTMLInputElement>(null);
  const ref = inputRef ?? fallbackRef;

  const pills: { key: string; value: string }[] = [];
  if (activeFacets) {
    for (const [k, vals] of Object.entries(activeFacets)) {
      for (const v of vals) {
        pills.push({ key: k, value: v });
      }
    }
  }

  return (
    <div className="search-bar">
      <div className="search-bar__row">
        <svg className="search-bar__icon" viewBox="0 0 16 16" width="14" height="14">
          <circle cx="6.5" cy="6.5" r="5" fill="none" stroke="currentColor" strokeWidth="1.5" />
          <line x1="10" y1="10" x2="14" y2="14" stroke="currentColor" strokeWidth="1.5" />
        </svg>
        <input
          ref={ref}
          className="search-bar__input"
          type="text"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          spellCheck={false}
        />
        {value ? (
          <button className="search-bar__clear" onClick={() => onChange("")} aria-label="Clear search">
            &times;
          </button>
        ) : null}
      </div>
      {pills.length > 0 ? (
        <div className="search-bar__pills">
          {pills.map((p) => (
            <span key={`${p.key}:${p.value}`} className="search-bar__pill">
              <span className="search-bar__pill-key">{p.key}:</span>
              {p.value}
              {onClearFacet ? (
                <button
                  className="search-bar__pill-x"
                  onClick={() => onClearFacet(p.key, p.value)}
                >
                  &times;
                </button>
              ) : null}
            </span>
          ))}
        </div>
      ) : null}
    </div>
  );
}
