import { type ReactNode } from "react";

type ExplorerLayoutProps = {
  sidebar: ReactNode;
  children: ReactNode;
  panel?: ReactNode;
};

export function ExplorerLayout({ sidebar, children, panel }: ExplorerLayoutProps) {
  return (
    <div className={`explorer ${panel ? "explorer--with-panel" : ""}`}>
      <aside className="explorer__sidebar">{sidebar}</aside>
      <div className="explorer__content">{children}</div>
      {panel ? <aside className="explorer__panel">{panel}</aside> : null}
    </div>
  );
}
